// Archivo: basico.js (PARTE 1: Preguntas 1 a 150)
export const preguntasNivel1 = [
  { id: 1, curso: "Red Hat System Administration I", pregunta: "¿Cuál es la diferencia entre un usuario normal y el usuario root en Linux?", opciones: ["El usuario root no puede ejecutar comandos de sistema.", "El usuario root tiene privilegios totales de administración, mientras que el normal tiene permisos limitados.", "No hay diferencia, ambos tienen acceso a todos los archivos.", "El usuario normal puede modificar el kernel, pero root no.", "El usuario root solo puede leer archivos, no modificarlos."], respuestaCorrecta: 1, explicacion: "El usuario root (superusuario) tiene acceso ilimitado a todos los comandos, archivos y configuraciones del sistema operativo." },
  { id: 2, curso: "Red Hat System Administration I", pregunta: "¿Para qué sirve el comando pwd?", opciones: ["Para cambiar la contraseña de un usuario.", "Para listar los archivos de un directorio.", "Para mostrar la ruta absoluta del directorio de trabajo actual (Print Working Directory).", "Para eliminar un directorio vacío.", "Para cambiar de directorio."], respuestaCorrecta: 2, explicacion: "pwd imprime la ruta completa del directorio en el que te encuentras actualmente." },
  { id: 3, curso: "Red Hat System Administration I", pregunta: "¿Cómo listarías todos los archivos, incluidos los ocultos, de un directorio?", opciones: ["ls -l", "ls -a", "ls -h", "ls -R", "list all"], respuestaCorrecta: 1, explicacion: "La bandera -a (all) muestra todos los archivos, incluyendo los que comienzan con un punto (ocultos)." },
  { id: 4, curso: "Red Hat System Administration I", pregunta: "¿Qué hace el comando cd ..?", opciones: ["Crea un directorio padre.", "Elimina el directorio actual.", "Te mueve al directorio padre o anterior en la jerarquía.", "Muestra el contenido del directorio actual.", "Cambia los permisos del directorio."], respuestaCorrecta: 2, explicacion: "Los dos puntos (..) representan el directorio padre, por lo que cd .. retrocede un nivel." },
  { id: 5, curso: "Red Hat System Administration I", pregunta: "¿Cuál es la función del comando ls -l?", opciones: ["Listar archivos en formato largo con detalles de permisos, propietario y tamaño.", "Listar solo los archivos ocultos.", "Listar archivos ordenados por fecha.", "Listar archivos en formato de árbol.", "Listar solo los directorios."], respuestaCorrecta: 0, explicacion: "La opción -l (long) muestra una lista detallada con permisos, enlaces, propietario, grupo, tamaño y fecha." },
  { id: 6, curso: "Red Hat System Administration I", pregunta: "¿Cómo crearías un directorio llamado practica1?", opciones: ["touch practica1", "mkdir practica1", "newdir practica1", "create practica1", "md practica1"], respuestaCorrecta: 1, explicacion: "El comando mkdir (make directory) se utiliza para crear nuevos directorios." },
  { id: 7, curso: "Red Hat System Administration I", pregunta: "¿Qué comando usarías para copiar un archivo a otro directorio?", opciones: ["mv", "cp", "copy", "dup", "clone"], respuestaCorrecta: 1, explicacion: "El comando cp (copy) duplica archivos o directorios en una nueva ubicación." },
  { id: 8, curso: "Red Hat System Administration I", pregunta: "¿Cómo renombrarías un archivo desde la terminal?", opciones: ["rename archivo nuevo_nombre", "mv archivo nuevo_nombre", "cp archivo nuevo_nombre", "name archivo nuevo_nombre", "mod archivo nuevo_nombre"], respuestaCorrecta: 1, explicacion: "El comando mv (move) se usa tanto para mover como para renombrar archivos." },
  { id: 9, curso: "Red Hat System Administration I", pregunta: "¿Qué hace el comando rm y por qué hay que usarlo con cuidado?", opciones: ["Elimina archivos o directorios permanentemente sin enviarlos a una papelera.", "Renombra archivos de forma segura.", "Comprime archivos para ahorrar espacio.", "Cambia los permisos de un archivo.", "Mueve archivos a la papelera de reciclaje."], respuestaCorrecta: 0, explicacion: "rm borra los datos inmediatamente del sistema de archivos, por lo que su recuperación es muy difícil." },
  { id: 10, curso: "Red Hat System Administration I", pregunta: "¿Cuál es la diferencia entre rm y rmdir?", opciones: ["No hay diferencia, son sinónimos.", "rm elimina archivos y rmdir elimina solo directorios vacíos.", "rmdir elimina archivos y rm elimina directorios.", "rm es para usuarios normales y rmdir solo para root.", "rmdir comprime directorios."], respuestaCorrecta: 1, explicacion: "rmdir está diseñado exclusivamente para borrar directorios que no contengan ningún archivo o subdirectorio." },
  { id: 11, curso: "Red Hat System Administration I", pregunta: "¿Cómo mostrarías el contenido de un archivo de texto en pantalla?", opciones: ["print", "show", "cat", "read", "display"], respuestaCorrecta: 2, explicacion: "El comando cat concatena y muestra el contenido de archivos en la salida estándar." },
  { id: 12, curso: "Red Hat System Administration I", pregunta: "¿Qué hace el comando touch?", opciones: ["Elimina un archivo.", "Crea un archivo vacío o actualiza su marca de tiempo.", "Cambia los permisos de un archivo.", "Muestra la fecha del sistema.", "Comprime un archivo."], respuestaCorrecta: 1, explicacion: "Si el archivo no existe, touch lo crea vacío. Si existe, actualiza su fecha de modificación." },
  { id: 13, curso: "Red Hat System Administration I", pregunta: "¿Cómo verías las primeras 10 líneas de un archivo?", opciones: ["tail archivo", "head archivo", "top archivo", "start archivo", "first archivo"], respuestaCorrecta: 1, explicacion: "El comando head muestra por defecto las primeras 10 líneas de un archivo." },
  { id: 14, curso: "Red Hat System Administration I", pregunta: "¿Cómo verías las últimas 10 líneas de un archivo?", opciones: ["head archivo", "bottom archivo", "tail archivo", "end archivo", "last archivo"], respuestaCorrecta: 2, explicacion: "El comando tail muestra por defecto las últimas 10 líneas de un archivo." },
  { id: 15, curso: "Red Hat System Administration I", pregunta: "¿Qué hace el operador de redirección >?", opciones: ["Añade contenido al final de un archivo.", "Sobrescribe el contenido de un archivo con la salida de un comando.", "Compara dos archivos.", "Ejecuta un comando en segundo plano.", "Redirige la entrada estándar."], respuestaCorrecta: 1, explicacion: "El operador > redirige la salida estándar, sobrescribiendo el archivo destino si ya existe." },
  { id: 16, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia existe entre > y >>?", opciones: ["> sobrescribe y >> añade (append) al final del archivo.", "No hay diferencia, son iguales.", "> es para archivos de texto y >> para binarios.", ">> sobrescribe y > añade al final.", "> es más rápido que >>."], respuestaCorrecta: 0, explicacion: ">> (doble mayor que) concatena o añade la nueva salida al final del archivo sin borrar lo existente." },
  { id: 17, curso: "Red Hat System Administration I", pregunta: "¿Cómo buscarías una palabra dentro de un archivo con grep?", opciones: ["find palabra archivo", "search palabra archivo", "grep palabra archivo", "look palabra archivo", "seek palabra archivo"], respuestaCorrecta: 2, explicacion: "grep filtra líneas de texto que coinciden con un patrón o palabra específica." },
  { id: 18, curso: "Red Hat System Administration I", pregunta: "¿Qué hace chmod 755 archivo?", opciones: ["Da permisos de lectura, escritura y ejecución al propietario, y solo lectura y ejecución a grupo y otros.", "Da todos los permisos a todos los usuarios.", "Elimina todos los permisos del archivo.", "Cambia el propietario del archivo.", "Oculta el archivo."], respuestaCorrecta: 0, explicacion: "7 (rwx) para el propietario, 5 (r-x) para el grupo y 5 (r-x) para otros." },
  { id: 19, curso: "Red Hat System Administration I", pregunta: "¿Qué significan los permisos r, w y x?", opciones: ["read, write, execute (lectura, escritura, ejecución).", "run, wait, exit.", "root, worker, xml.", "read, wait, xfer.", "rename, write, execute."], respuestaCorrecta: 0, explicacion: "Son las abreviaturas en inglés de los permisos básicos: leer, escribir y ejecutar." },
  { id: 20, curso: "Red Hat System Administration I", pregunta: "¿Cómo cambias el propietario de un archivo?", opciones: ["chmod", "chown", "chgrp", "usermod", "passwd"], respuestaCorrecta: 1, explicacion: "chown (change owner) modifica el usuario y/o grupo propietario de un archivo o directorio." },
  { id: 21, curso: "Red Hat System Administration I", pregunta: "¿Qué hace chown?", opciones: ["Cambia los permisos de lectura/escritura.", "Cambia el propietario y/o grupo de un archivo.", "Cambia la contraseña del propietario.", "Crea un nuevo propietario.", "Elimina el propietario de un archivo."], respuestaCorrecta: 1, explicacion: "Su función principal es reasignar la propiedad de archivos o directorios a un usuario o grupo específico." },
  { id: 22, curso: "Red Hat System Administration I", pregunta: "¿Cómo identificarías el tipo de archivo de un elemento en Linux?", opciones: ["type archivo", "file archivo", "stat archivo", "info archivo", "ls -type archivo"], respuestaCorrecta: 1, explicacion: "El comando file examina el contenido del archivo para determinar su tipo, no solo se basa en la extensión." },
  { id: 23, curso: "Red Hat System Administration I", pregunta: "¿Qué es un enlace simbólico?", opciones: ["Una copia exacta del archivo original.", "Un acceso directo que apunta a la ruta de otro archivo o directorio.", "Un archivo comprimido.", "Un archivo de solo lectura.", "Un archivo del sistema operativo."], respuestaCorrecta: 1, explicacion: "Es similar a un acceso directo en Windows; apunta a la ubicación del original, pero es un archivo independiente." },
  { id: 24, curso: "Red Hat System Administration I", pregunta: "¿Cuál es la diferencia entre un enlace duro y un enlace simbólico?", opciones: ["No hay diferencia.", "El enlace duro apunta al mismo inodo, el simbólico apunta a la ruta del nombre.", "El enlace duro solo funciona en red.", "El enlace simbólico ocupa más espacio en disco que el original.", "El enlace duro se rompe si se mueve el original."], respuestaCorrecta: 1, explicacion: "Un hard link comparte el mismo inodo (datos), mientras que un soft link (simbólico) es un puntero a una ruta." },
  { id: 25, curso: "Red Hat System Administration I", pregunta: "¿Cómo comprobarías cuánto espacio libre hay en el sistema?", opciones: ["du", "df", "free", "space", "mem"], respuestaCorrecta: 1, explicacion: "df (disk free) muestra el espacio disponible en los sistemas de archivos montados." },
  { id: 26, curso: "Red Hat System Administration I", pregunta: "¿Qué comando usarías para ver el uso de memoria?", opciones: ["df", "meminfo", "free", "ram", "topmem"], respuestaCorrecta: 2, explicacion: "El comando free muestra la cantidad total, usada y libre de memoria RAM y swap." },
  { id: 27, curso: "Red Hat System Administration I", pregunta: "¿Cómo listarías los procesos en ejecución?", opciones: ["proc", "run", "ps", "tasks", "list"], respuestaCorrecta: 2, explicacion: "ps (process status) muestra una instantánea de los procesos actuales." },
  { id: 28, curso: "Red Hat System Administration I", pregunta: "¿Qué hace el comando ps aux?", opciones: ["Muestra solo los procesos del usuario actual.", "Muestra todos los procesos de todos los usuarios con detalles completos.", "Elimina todos los procesos.", "Reinicia los servicios del sistema.", "Muestra solo los procesos en segundo plano."], respuestaCorrecta: 1, explicacion: "a (todos los usuarios), u (formato detallado con usuario), x (procesos sin terminal de control)." },
  { id: 29, curso: "Red Hat System Administration I", pregunta: "¿Cómo terminarías un proceso por su PID?", opciones: ["stop PID", "end PID", "kill PID", "delete PID", "close PID"], respuestaCorrecta: 2, explicacion: "El comando kill envía una señal (por defecto SIGTERM) para terminar un proceso especificando su ID." },
  { id: 30, curso: "Red Hat System Administration I", pregunta: "¿Qué información muestra top?", opciones: ["Solo el uso de disco.", "Una vista dinámica y en tiempo real de los procesos y el uso de recursos del sistema.", "La configuración de red.", "El historial de comandos.", "Los archivos de log."], respuestaCorrecta: 1, explicacion: "top es un monitor de sistema que muestra procesos, uso de CPU, memoria y carga del sistema en tiempo real." },
  { id: 31, curso: "Red Hat System Administration I", pregunta: "¿Cómo descomprimirías un archivo .tar.gz?", opciones: ["tar -cvf archivo.tar.gz", "tar -xzvf archivo.tar.gz", "unzip archivo.tar.gz", "decompress archivo.tar.gz", "extract archivo.tar.gz"], respuestaCorrecta: 1, explicacion: "x (extraer), z (descomprimir con gzip), v (verboso), f (archivo)." },
  { id: 32, curso: "Red Hat System Administration I", pregunta: "¿Qué hace el comando tar -cvf?", opciones: ["Descomprime un archivo.", "Crea un archivo tar (empaquetado) mostrando el proceso.", "Comprime con algoritmo zip.", "Verifica la integridad de un archivo.", "Cambia los permisos de un archivo tar."], respuestaCorrecta: 1, explicacion: "c (crear), v (verboso), f (especificar nombre del archivo). No comprime, solo empaqueta." },
  { id: 33, curso: "Red Hat System Administration I", pregunta: "¿Cómo agregarías permisos de ejecución a un script?", opciones: ["chmod +x script.sh", "chmod -x script.sh", "chown +x script.sh", "execute script.sh", "run script.sh"], respuestaCorrecta: 0, explicacion: "El operador +x añade el permiso de ejecución (eXecute) al archivo." },
  { id: 34, curso: "Red Hat System Administration I", pregunta: "¿Cómo ejecutarías un script de Bash?", opciones: ["run script.sh", "play script.sh", "./script.sh", "open script.sh", "start script.sh"], respuestaCorrecta: 2, explicacion: "./ indica al sistema que ejecute el archivo ubicado en el directorio actual." },
  { id: 35, curso: "Red Hat System Administration I", pregunta: "¿Qué es una variable de entorno?", opciones: ["Una variable que solo existe dentro de un script.", "Una variable global disponible para todos los procesos hijos del shell.", "Un archivo de configuración.", "Un tipo de permiso de Linux.", "Una contraseña de usuario."], respuestaCorrecta: 1, explicacion: "Se exporta al entorno del sistema y está disponible para cualquier programa o script que se ejecute." },
  { id: 36, curso: "Red Hat System Administration I", pregunta: "¿Cuál es la diferencia entre una variable local y una de entorno?", opciones: ["No hay diferencia.", "La local solo existe en el shell actual, la de entorno se hereda a procesos hijos.", "La de entorno es solo para root.", "La local ocupa más memoria.", "La de entorno no se puede modificar."], respuestaCorrecta: 1, explicacion: "Las variables locales se destruyen al cerrar el shell, mientras que las de entorno (exportadas) persisten en procesos derivados." },
  { id: 37, curso: "Red Hat System Administration I", pregunta: "¿Cómo verías el contenido de una variable en Bash?", opciones: ["print VAR", "show VAR", "echo $VAR", "cat VAR", "read VAR"], respuestaCorrecta: 2, explicacion: "El comando echo seguido del signo $ imprime el valor almacenado en la variable." },
  { id: 38, curso: "Red Hat System Administration I", pregunta: "¿Qué hace el archivo .bashrc?", opciones: ["Almacena el historial de comandos.", "Contiene configuraciones y alias que se cargan al iniciar un shell interactivo.", "Es el archivo de contraseñas.", "Define las particiones del disco.", "Configura el firewall."], respuestaCorrecta: 1, explicacion: "Se ejecuta cada vez que se abre una nueva terminal, permitiendo personalizar el entorno del usuario." },
  { id: 39, curso: "Red Hat System Administration I", pregunta: "¿Cómo verificarías la versión del sistema operativo Red Hat?", opciones: ["version", "cat /etc/redhat-release", "uname -v", "os-check", "rhel-version"], respuestaCorrecta: 1, explicacion: "El archivo /etc/redhat-release contiene el nombre y la versión específica de la distribución." },
  { id: 40, curso: "Red Hat System Administration I", pregunta: "¿Qué es SELinux y para qué sirve?", opciones: ["Un antivirus para Linux.", "Un módulo de seguridad que proporciona control de acceso obligatorio (MAC).", "Un gestor de paquetes.", "Un protocolo de red.", "Un sistema de archivos."], respuestaCorrecta: 1, explicacion: "Security-Enhanced Linux restringe los programas a un conjunto mínimo de privilegios para mejorar la seguridad." },
  { id: 41, curso: "CCNA M3", pregunta: "¿Qué es el enrutamiento estático?", opciones: ["Rutas aprendidas automáticamente por protocolos.", "Rutas configuradas manualmente por el administrador de red.", "Rutas que cambian dinámicamente según el tráfico.", "Rutas que solo funcionan en redes LAN.", "Rutas asignadas por DHCP."], respuestaCorrecta: 1, explicacion: "El administrador escribe manualmente las rutas en la tabla de enrutamiento, no hay intercambio automático." },
  { id: 42, curso: "CCNA M3", pregunta: "¿Qué es el enrutamiento dinámico?", opciones: ["Configuración manual de cada ruta.", "Protocolos que permiten a los routers compartir información de rutas automáticamente.", "Enrutamiento basado solo en direcciones MAC.", "Un tipo de cableado de red.", "Asignación de IPs a usuarios."], respuestaCorrecta: 1, explicacion: "Usa protocolos como OSPF o EIGRP para descubrir redes remotas y adaptarse a cambios en la topología." },
  { id: 43, curso: "CCNA M3", pregunta: "¿Cuál es la diferencia entre una ruta directamente conectada y una aprendida?", opciones: ["No hay diferencia.", "La conectada pertenece a una interfaz activa del router, la aprendida proviene de otro router.", "La aprendida es más rápida.", "La conectada requiere configuración manual.", "La aprendida tiene distancia administrativa 0."], respuestaCorrecta: 1, explicacion: "Las conectadas (C) aparecen al configurar una IP y activar la interfaz; las aprendidas (O, D, R) vienen de protocolos." },
  { id: 44, curso: "CCNA M3", pregunta: "¿Qué función cumple una tabla de routing?", opciones: ["Almacenar contraseñas de los routers.", "Determinar el mejor camino para enviar paquetes hacia una red de destino.", "Filtrar tráfico de internet.", "Asignar direcciones IP.", "Monitorear el ancho de banda."], respuestaCorrecta: 1, explicacion: "Es la base de datos que el router consulta para decidir por qué interfaz reenviar un paquete." },
  { id: 45, curso: "CCNA M3", pregunta: "¿Qué es una ruta por defecto?", opciones: ["La ruta con mayor métrica.", "Una ruta comodín (0.0.0.0/0) usada cuando no hay una ruta específica para el destino.", "La primera ruta configurada en el router.", "Una ruta que solo funciona en redes locales.", "Una ruta estática hacia un servidor DNS."], respuestaCorrecta: 1, explicacion: "Actúa como puerta de enlace de último recurso para cualquier tráfico que no coincida con otras rutas." },
  { id: 46, curso: "CCNA M3", pregunta: "¿Cómo configuras una ruta estática en un router Cisco?", opciones: ["route add red mascara interfaz", "ip route red_destino mascara sig_salida", "set route red mascara", "static ip red mascara", "add path red mascara"], respuestaCorrecta: 1, explicacion: "La sintaxis correcta en modo de configuración global es 'ip route [red] [máscara] [siguiente salto o interfaz]'." },
  { id: 47, curso: "CCNA M3", pregunta: "¿Qué hace el comando show ip route?", opciones: ["Muestra la configuración de las interfaces.", "Muestra la tabla de enrutamiento completa del router.", "Muestra los protocolos de enrutamiento activos.", "Muestra la tabla ARP.", "Muestra el estado de los cables."], respuestaCorrecta: 1, explicacion: "Es el comando principal para verificar qué redes conoce el router y cómo llegar a ellas." },
  { id: 48, curso: "CCNA M3", pregunta: "¿Cómo identificarías la interfaz de salida hacia una red remota?", opciones: ["Mirando la tabla MAC.", "Consultando la tabla de enrutamiento (show ip route).", "Usando el comando ping.", "Revisando el archivo de configuración del switch.", "Consultando el servidor DHCP."], respuestaCorrecta: 1, explicacion: "La tabla de enrutamiento indica explícitamente la interfaz de salida o la dirección del siguiente salto." },
  { id: 49, curso: "CCNA M3", pregunta: "¿Qué es una métrica en routing?", opciones: ["La dirección IP del router.", "Un valor numérico que usan los protocolos para determinar la mejor ruta.", "El nombre del protocolo de enrutamiento.", "La velocidad del cable de red.", "El número de serie del router."], respuestaCorrecta: 1, explicacion: "Cuanto menor sea la métrica, más preferida es la ruta (ej. saltos en RIP, costo en OSPF)." },
  { id: 50, curso: "CCNA M3", pregunta: "¿Qué protocolo usa métrica basada en cantidad de saltos?", opciones: ["OSPF", "EIGRP", "RIP", "BGP", "IS-IS"], respuestaCorrecta: 2, explicacion: "RIP (Routing Information Protocol) utiliza el conteo de saltos (hops) como única métrica, con un máximo de 15." },
  { id: 51, curso: "CCNA M3", pregunta: "¿Qué es RIP?", opciones: ["Un protocolo de estado de enlace.", "Un protocolo de vector distancia antiguo que usa conteo de saltos.", "Un protocolo de enrutamiento de Cisco propietario.", "Un protocolo para redes IPv6 solamente.", "Un protocolo de seguridad de red."], respuestaCorrecta: 1, explicacion: "Routing Information Protocol es un protocolo de vector distancia clásico, hoy en día poco usado por su lenta convergencia." },
  { id: 52, curso: "CCNA M3", pregunta: "¿Qué limitación importante tiene RIP?", opciones: ["No soporta VLANs.", "Tiene un límite máximo de 15 saltos, considerando 16 como inalcanzable.", "No soporta direcciones IP.", "Requiere configuración manual de cada ruta.", "Solo funciona en redes inalámbricas."], respuestaCorrecta: 1, explicacion: "Esta limitación lo hace inviable para redes empresariales grandes o complejas." },
  { id: 53, curso: "CCNA M3", pregunta: "¿Qué es OSPF?", opciones: ["Un protocolo de vector distancia.", "Un protocolo de estado de enlace (Link-State) estándar abierto.", "Un protocolo propietario de Cisco.", "Un protocolo de capa 2.", "Un protocolo de asignación de IPs."], respuestaCorrecta: 1, explicacion: "Open Shortest Path First construye un mapa completo de la red (LSDB) para calcular la ruta más corta." },
  { id: 54, curso: "CCNA M3", pregunta: "¿Qué ventaja tiene OSPF frente a RIP?", opciones: ["Es más fácil de configurar.", "Converge más rápido, no tiene límite de saltos y usa ancho de banda como métrica.", "Usa menos memoria RAM.", "No requiere área backbone.", "Es un protocolo de capa 2."], respuestaCorrecta: 1, explicacion: "OSPF es escalable, eficiente y toma decisiones de enrutamiento más inteligentes basadas en el costo de la interfaz." },
  { id: 55, curso: "CCNA M3", pregunta: "¿Qué significa que OSPF use áreas?", opciones: ["Que divide la red en segmentos lógicos para reducir el tráfico de control y el tamaño de la LSDB.", "Que solo funciona en redes inalámbricas.", "Que asigna áreas geográficas a los routers.", "Que limita el número de usuarios por router.", "Que encripta el tráfico por zonas."], respuestaCorrecta: 0, explicacion: "La jerarquía de áreas permite que OSPF escale a redes muy grandes sin saturar a los routers con actualizaciones." },
  { id: 56, curso: "CCNA M3", pregunta: "¿Qué es un área backbone en OSPF?", opciones: ["El área con más usuarios.", "El Área 0, que es el núcleo central al que deben conectarse todas las demás áreas.", "Un área de seguridad.", "El área que no tiene routers.", "El área de administración."], respuestaCorrecta: 1, explicacion: "Todo el tráfico entre diferentes áreas OSPF debe pasar obligatoriamente por el Área 0." },
  { id: 57, curso: "CCNA M3", pregunta: "¿Qué hace el comando router ospf 1?", opciones: ["Inicia el proceso de enrutamiento OSPF con un ID de proceso local de 1.", "Configura el área 1.", "Establece el router ID en 1.", "Habilita OSPF en todas las interfaces.", "Borra la configuración de OSPF."], respuestaCorrecta: 0, explicacion: "El número '1' es el ID del proceso, que es local al router y no necesita coincidir con otros routers." },
  { id: 58, curso: "CCNA M3", pregunta: "¿Cómo anuncias una red en OSPF?", opciones: ["ip network red mascara", "network red wildcard area X", "add ospf network", "ospf network red", "advertise network red"], respuestaCorrecta: 1, explicacion: "Se usa el comando 'network [dirección de red] [máscara wildcard] area [número de área]'." },
  { id: 59, curso: "CCNA M3", pregunta: "¿Qué es el costo en OSPF?", opciones: ["El precio de la licencia del router.", "La métrica de OSPF, calculada inversamente proporcional al ancho de banda de la interfaz.", "El número de saltos.", "La cantidad de memoria usada.", "El tiempo de convergencia."], respuestaCorrecta: 1, explicacion: "Costo = Ancho de banda de referencia / Ancho de banda de la interfaz. A mayor ancho de banda, menor costo." },
  { id: 60, curso: "CCNA M3", pregunta: "¿Qué es una adyacencia entre vecinos OSPF?", opciones: ["Dos routers conectados físicamente.", "Una relación formada entre routers OSPF que han intercambiado con éxito sus bases de datos de estado de enlace.", "Dos routers con la misma dirección IP.", "Un cable cruzado entre switches.", "Una conexión Wi-Fi entre routers."], respuestaCorrecta: 1, explicacion: "La adyacencia es el estado final (FULL) donde los routers comparten la misma visión de la red." },
  { id: 61, curso: "CCNA M3", pregunta: "¿Qué sucede si dos routers OSPF no coinciden en el área?", opciones: ["Se comunican normalmente.", "No formarán adyacencia ni intercambiarán rutas.", "El router con el área más alta domina.", "Se crea un túnel automático.", "Se reinician automáticamente."], respuestaCorrecta: 1, explicacion: "Los parámetros del área (incluido el número de área) deben coincidir exactamente para que se forme la vecindad." },
  { id: 62, curso: "CCNA M3", pregunta: "¿Qué es EIGRP?", opciones: ["Un protocolo de estado de enlace estándar.", "Enhanced Interior Gateway Routing Protocol, un protocolo avanzado de vector distancia (híbrido) de Cisco.", "Un protocolo de enrutamiento para redes IPv6 solamente.", "Un protocolo de seguridad.", "Un protocolo de capa 2."], respuestaCorrecta: 1, explicacion: "EIGRP combina características de vector distancia y estado de enlace, ofreciendo convergencia rápida y bajo uso de ancho de banda." },
  { id: 63, curso: "CCNA M3", pregunta: "¿Qué tipo de protocolo es EIGRP?", opciones: ["Vector distancia puro.", "Estado de enlace puro.", "Vector distancia avanzado o híbrido.", "Protocolo de puerta de enlace exterior.", "Protocolo de enrutamiento estático."], respuestaCorrecta: 2, explicacion: "Aunque Cisco lo llamaba 'híbrido', técnicamente es un protocolo de vector distancia avanzado que usa DUAL." },
  { id: 64, curso: "CCNA M3", pregunta: "¿Qué significa convergencia en routing?", opciones: ["Cuando todos los routers tienen la misma dirección IP.", "El estado en que todos los routers tienen una visión consistente y precisa de la topología de la red.", "Cuando se apaga la red.", "La velocidad del cable de fibra óptica.", "La suma de todas las métricas."], respuestaCorrecta: 1, explicacion: "Una red converge cuando los cambios en la topología han sido procesados y las tablas de enrutamiento están actualizadas." },
  { id: 65, curso: "CCNA M3", pregunta: "¿Qué ocurre cuando falla un enlace en una red con routing dinámico?", opciones: ["La red deja de funcionar permanentemente.", "El protocolo detecta la falla y recalcula las rutas para usar un camino alternativo.", "El administrador debe reconfigurar todo manualmente.", "Los paquetes se pierden para siempre.", "El router se reinicia."], respuestaCorrecta: 1, explicacion: "Esta es la principal ventaja del routing dinámico: la tolerancia a fallos y la recalculación automática." },
  { id: 66, curso: "CCNA M3", pregunta: "¿Qué es el balanceo de carga en routing?", opciones: ["Distribuir el tráfico de red a través de múltiples rutas hacia el mismo destino.", "Apagar routers para ahorrar energía.", "Aumentar el ancho de banda de una sola interfaz.", "Filtrar paquetes maliciosos.", "Asignar IPs dinámicamente."], respuestaCorrecta: 0, explicacion: "Permite utilizar eficientemente múltiples enlaces, ya sea que tengan la misma métrica (igual costo) o diferente." },
  { id: 67, curso: "CCNA M3", pregunta: "¿Qué diferencia hay entre una ruta administrativa y una métrica?", opciones: ["Son lo mismo.", "La distancia administrativa compara la confiabilidad entre diferentes protocolos; la métrica compara rutas dentro del mismo protocolo.", "La métrica es para redes LAN y la administrativa para WAN.", "La administrativa es configurada por el usuario y la métrica por el hardware.", "No existe la ruta administrativa."], respuestaCorrecta: 1, explicacion: "La DA decide qué protocolo gana si hay rutas al mismo destino; la métrica decide la mejor ruta dentro de ese protocolo ganador." },
  { id: 68, curso: "CCNA M3", pregunta: "¿Qué es la distancia administrativa?", opciones: ["La cantidad de routers en la red.", "Un valor numérico que indica la confiabilidad de una fuente de información de enrutamiento.", "La distancia física entre dos routers.", "El número de usuarios en la red.", "La velocidad de la interfaz."], respuestaCorrecta: 1, explicacion: "Cuanto menor sea el valor (ej. 1 para estática, 110 para OSPF), más confiable se considera la ruta." },
  { id: 69, curso: "CCNA M3", pregunta: "¿Qué valor tiene menor distancia administrativa, una ruta estática o una aprendida por OSPF?", opciones: ["OSPF, porque es dinámico.", "La ruta estática (1) es más confiable que OSPF (110).", "Ambas tienen el mismo valor.", "Depende del fabricante del router.", "Ninguna tiene distancia administrativa."], respuestaCorrecta: 1, explicacion: "El administrador asume que una ruta configurada manualmente (estática) es más intencional y confiable que una aprendida." },
  { id: 70, curso: "CCNA M3", pregunta: "¿Cómo verías los vecinos OSPF en un router Cisco?", opciones: ["show ip ospf", "show ip ospf neighbor", "show neighbors", "show ip route", "show ospf interfaces"], respuestaCorrecta: 1, explicacion: "Este comando muestra el estado de las adyacencias, incluyendo el Router ID vecino, la interfaz y el estado (ej. FULL)." },
  { id: 71, curso: "CCNA M3", pregunta: "¿Qué hace el comando show ip protocols?", opciones: ["Muestra la configuración de las interfaces.", "Resume los parámetros y el estado de los protocolos de enrutamiento activos.", "Muestra la tabla MAC.", "Muestra el historial de comandos.", "Reinicia los protocolos de enrutamiento."], respuestaCorrecta: 1, explicacion: "Es muy útil para verificar qué redes se están anunciando, los temporizadores y las distancias administrativas configuradas." },
  { id: 72, curso: "CCNA M3", pregunta: "¿Qué información entrega show running-config en relación con routing?", opciones: ["Muestra la tabla de enrutamiento actual.", "Muestra las configuraciones de routing que están activas en la memoria RAM del router.", "Muestra el tráfico en tiempo real.", "Muestra las contraseñas en texto plano.", "Muestra el estado de los cables."], respuestaCorrecta: 1, explicacion: "Permite ver exactamente qué comandos de routing (static, ospf, eigrp) se han escrito en la configuración." },
  { id: 73, curso: "CCNA M3", pregunta: "¿Qué es un router de borde?", opciones: ["Un router que solo conecta PCs.", "Un router ubicado en el límite de una red, conectándola con redes externas o a Internet.", "Un router que no tiene interfaces.", "Un switch de capa 2.", "Un servidor de archivos."], respuestaCorrecta: 1, explicacion: "Es el punto de salida de la red local, a menudo donde se aplica la política de seguridad y NAT." },
  { id: 74, curso: "CCNA M3", pregunta: "¿Qué es una interfaz pasiva en un protocolo de routing?", opciones: ["Una interfaz dañada.", "Una interfaz que participa en el proceso de routing pero no envía ni recibe actualizaciones de protocolo por ella.", "Una interfaz sin dirección IP.", "Una interfaz que solo recibe tráfico.", "Una interfaz de fibra óptica."], respuestaCorrecta: 1, explicacion: "Se usa en redes LAN para evitar enviar actualizaciones de routing innecesarias a los PCs, mejorando la seguridad y eficiencia." },
  { id: 75, curso: "CCNA M3", pregunta: "¿Por qué se usan máscaras wildcard en OSPF?", opciones: ["Para encriptar el tráfico.", "Para especificar qué interfaces exactas o rangos de IP participarán en el proceso OSPF.", "Para ocultar la dirección IP del router.", "Para aumentar la velocidad de la red.", "Para asignar contraseñas."], respuestaCorrecta: 1, explicacion: "La máscara wildcard (inversa a la de subred) indica al router qué bits de la dirección IP deben coincidir para incluir la interfaz." },
  { id: 76, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es HTML?", opciones: ["Un lenguaje de programación.", "HyperText Markup Language, un lenguaje de marcado para estructurar contenido web.", "Un sistema de gestión de bases de datos.", "Un protocolo de red.", "Un lenguaje de estilos."], respuestaCorrecta: 1, explicacion: "HTML no es un lenguaje de programación, sino de marcado que define la estructura y el significado semántico del contenido." },
  { id: 77, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Para qué sirve la etiqueta <html>?", opciones: ["Define el título de la página.", "Es el elemento raíz que envuelve todo el contenido de un documento HTML.", "Crea un párrafo.", "Inserta una imagen.", "Define el cuerpo de la página."], respuestaCorrecta: 1, explicacion: "Indica al navegador que el contenido del archivo está escrito en HTML y contiene a <head> y <body>." },
  { id: 78, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cuál es la diferencia entre <head> y <body>?", opciones: ["No hay diferencia.", "<head> contiene metadatos e información para el navegador, <body> contiene el contenido visible para el usuario.", "<head> es para imágenes y <body> para texto.", "<body> va antes que <head>.", "<head> es obligatorio y <body> opcional."], respuestaCorrecta: 1, explicacion: "El head es la cabecera invisible (título, enlaces CSS), el body es el cuerpo visible de la página." },
  { id: 79, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace la etiqueta <title>?", opciones: ["Crea un título grande en la página.", "Define el título del documento que aparece en la pestaña del navegador.", "Cambia el color del texto.", "Inserta un vídeo.", "Crea un enlace."], respuestaCorrecta: 1, explicacion: "Debe ir dentro de <head> y es fundamental para el SEO y la experiencia de usuario en las pestañas." },
  { id: 80, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Para qué sirve <h1> y en qué se diferencia de <h6>?", opciones: ["Son iguales.", "<h1> define el encabezado más importante y grande, <h6> el menos importante y más pequeño.", "<h6> es más importante que <h1>.", "<h1> es para listas y <h6> para párrafos.", "No existen las etiquetas h1 a h6."], respuestaCorrecta: 1, explicacion: "Representan una jerarquía de importancia, siendo h1 el título principal y h6 un subencabezado de menor nivel." },
  { id: 81, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace la etiqueta <p>?", opciones: ["Crea una imagen.", "Define un párrafo de texto.", "Crea un enlace.", "Inserta un salto de línea.", "Crea una tabla."], respuestaCorrecta: 1, explicacion: "La etiqueta 'p' (paragraph) agrega un bloque de texto con márgenes superior e inferior automáticos." },
  { id: 82, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo insertas un enlace en HTML?", opciones: ["<link href='url'>", "<a href='url'>Texto</a>", "<href url='url'>", "<url>Texto</url>", "<nav href='url'>"], respuestaCorrecta: 1, explicacion: "La etiqueta de anclaje <a> con el atributo href (hypertext reference) crea hipervínculos." },
  { id: 83, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué atributo se usa para abrir un enlace en una nueva pestaña?", opciones: ["target='_self'", "target='_blank'", "new='true'", "window='new'", "open='true'"], respuestaCorrecta: 1, explicacion: "target='_blank' indica al navegador que debe abrir el recurso en un nuevo contexto de navegación." },
  { id: 84, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo insertas una imagen en una página web?", opciones: ["<image src='url'>", "<img src='url' alt='descripción'>", "<pic href='url'>", "<img href='url'>", "<src img='url'>"], respuestaCorrecta: 1, explicacion: "La etiqueta <img> es vacía (no tiene cierre) y requiere el atributo src para la fuente de la imagen." },
  { id: 85, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué atributo es obligatorio en una etiqueta <img> para accesibilidad?", opciones: ["title", "alt", "srcset", "width", "class"], respuestaCorrecta: 1, explicacion: "El atributo alt proporciona un texto alternativo que los lectores de pantalla leen a usuarios con discapacidad visual." },
  { id: 86, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una lista ordenada?", opciones: ["Una lista con viñetas.", "Una lista cuyos elementos tienen un orden numérico o alfabético, creada con <ol>.", "Una lista sin orden.", "Una tabla de datos.", "Un menú de navegación."], respuestaCorrecta: 1, explicacion: "<ol> (ordered list) numera automáticamente los elementos <li> que contiene." },
  { id: 87, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una lista desordenada?", opciones: ["Una lista numerada.", "Una lista con viñetas (puntos), creada con <ul>.", "Una lista vacía.", "Un formulario.", "Un enlace."], respuestaCorrecta: 1, explicacion: "<ul> (unordered list) muestra los elementos <li> con marcadores (bullets) en lugar de números." },
  { id: 88, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre <div> y <span>?", opciones: ["No hay diferencia.", "<div> es un contenedor de nivel de bloque, <span> es un contenedor en línea.", "<span> es más grande que <div>.", "<div> es solo para imágenes.", "<span> crea saltos de línea."], respuestaCorrecta: 1, explicacion: "<div> ocupa todo el ancho disponible y salta de línea; <span> solo ocupa el espacio de su contenido, sin saltar." },
  { id: 89, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Para qué sirve CSS?", opciones: ["Para programar la lógica del servidor.", "Cascading Style Sheets, para controlar la presentación, diseño y estilo de un documento HTML.", "Para crear bases de datos.", "Para encriptar contraseñas.", "Para definir la estructura del HTML."], respuestaCorrecta: 1, explicacion: "CSS separa el contenido (HTML) de su presentación visual (colores, fuentes, disposición)." },
  { id: 90, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una hoja de estilo externa?", opciones: ["CSS escrito dentro de la etiqueta <style>.", "Un archivo .css separado vinculado al HTML mediante la etiqueta <link>.", "CSS escrito dentro de los atributos style de las etiquetas.", "Un archivo JavaScript.", "Un archivo de imagen."], respuestaCorrecta: 1, explicacion: "Es la práctica recomendada, ya que permite reutilizar los mismos estilos en múltiples páginas HTML." },
  { id: 91, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cuál es la diferencia entre selector de clase y selector de id?", opciones: ["No hay diferencia.", "La clase (.) puede usarse en múltiples elementos, el id (#) debe ser único en todo el documento.", "El id es para CSS y la clase para JavaScript.", "La clase es más específica que el id.", "El id se usa con un punto y la clase con un numeral."], respuestaCorrecta: 1, explicacion: "Un id identifica de forma única un solo elemento, mientras que una clase agrupa varios elementos con estilos comunes." },
  { id: 92, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué significa el modelo de caja en CSS?", opciones: ["Un tipo de borde.", "El concepto de que cada elemento HTML es una caja rectangular compuesta por margen, borde, relleno y contenido.", "Una propiedad para ocultar elementos.", "Un tipo de diseño responsivo.", "Una etiqueta de HTML5."], respuestaCorrecta: 1, explicacion: "Box model describe cómo se calculan el ancho y alto totales de un elemento (content + padding + border + margin)." },
  { id: 93, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué propiedades componen el box model?", opciones: ["color, font, size, weight.", "content, padding, border, margin.", "width, height, display, position.", "top, right, bottom, left.", "flex, grid, block, inline."], respuestaCorrecta: 1, explicacion: "Desde adentro hacia afuera: el contenido, el relleno (padding), el borde (border) y el margen exterior (margin)." },
  { id: 94, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cómo centrarías horizontalmente un bloque con CSS?", opciones: ["text-align: center;", "margin: 0 auto; (con un ancho definido).", "align: middle;", "center: true;", "float: center;"], respuestaCorrecta: 1, explicacion: "Establecer márgenes izquierdo y derecho en 'auto' distribuye el espacio restante equitativamente a ambos lados." },
  { id: 95, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace display: flex;", opciones: ["Oculta el elemento.", "Convierte el contenedor en un contenedor flexible, facilitando la alineación y distribución de sus hijos.", "Convierte el elemento en un bloque.", "Hace que el elemento flote a la derecha.", "Crea una cuadrícula."], respuestaCorrecta: 1, explicacion: "Flexbox es un modelo de diseño unidimensional ideal para distribuir espacio y alinear elementos en una fila o columna." },
  { id: 96, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es JavaScript en el desarrollo web?", opciones: ["Un lenguaje de marcado.", "Un lenguaje de programación que permite agregar interactividad y comportamiento dinámico a las páginas web.", "Un framework de CSS.", "Un sistema de gestión de bases de datos.", "Un protocolo de internet."], respuestaCorrecta: 1, explicacion: "Es el lenguaje que permite manipular el DOM, responder a eventos del usuario y comunicarse con servidores." },
  { id: 97, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre let, const y var?", opciones: ["No hay diferencia.", "var tiene alcance de función y hoisting, let tiene alcance de bloque, const es una variable de bloque que no puede reasignarse.", "const es para números y let para texto.", "var es la más moderna.", "let y const son lo mismo."], respuestaCorrecta: 1, explicacion: "let y const (ES6) solucionan los problemas de alcance y hoisting de var, siendo const para valores que no cambiarán de referencia." },
  { id: 98, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace document.getElementById()?", opciones: ["Crea un nuevo elemento.", "Selecciona y devuelve el elemento del DOM que tiene el atributo id especificado.", "Elimina un elemento.", "Cambia el color de fondo.", "Añade un evento."], respuestaCorrecta: 1, explicacion: "Es uno de los métodos más rápidos y comunes para acceder a un nodo específico del DOM mediante su identificador único." },
  { id: 99, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es el DOM?", opciones: ["Un lenguaje de programación.", "Document Object Model, una representación en forma de árbol de la estructura de un documento HTML.", "Un servidor web.", "Un tipo de base de datos.", "Un protocolo de red."], respuestaCorrecta: 1, explicacion: "El DOM permite que lenguajes como JavaScript accedan y manipulen el contenido, estructura y estilo de la página." },
  { id: 100, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia existe entre frontend y backend?", opciones: ["No hay diferencia.", "Frontend es la parte visual e interactiva que ve el usuario; backend es la lógica del servidor, base de datos y APIs.", "Frontend usa Python y backend usa HTML.", "Frontend es para móviles y backend para PC.", "Frontend es más seguro que backend."], respuestaCorrecta: 1, explicacion: "El frontend (cliente) se ejecuta en el navegador; el backend (servidor) procesa datos y reglas de negocio de forma oculta." },
  { id: 101, curso: "Algoritmia", pregunta: "¿Qué es un algoritmo?", opciones: ["Un lenguaje de programación.", "Una secuencia finita, ordenada y precisa de pasos para resolver un problema o realizar una tarea.", "Un tipo de computadora.", "Un error en el código.", "Un sistema operativo."], respuestaCorrecta: 1, explicacion: "Es el concepto fundamental de la informática: la receta lógica independiente del lenguaje de programación." },
  { id: 102, curso: "Algoritmia", pregunta: "¿Cuáles son las características de un buen algoritmo?", opciones: ["Debe ser largo y complejo.", "Debe ser preciso, definido, finito y tener entradas/salidas claras.", "Debe usar solo números.", "No debe tener fin.", "Debe estar escrito en inglés."], respuestaCorrecta: 1, explicacion: "Un algoritmo debe terminar en algún momento (finitud), cada paso debe ser claro (definido) y producir resultados." },
  { id: 103, curso: "Algoritmia", pregunta: "¿Qué diferencia existe entre algoritmo y programa?", opciones: ["Son exactamente lo mismo.", "El algoritmo es la idea o lógica abstracta; el programa es la implementación de esa lógica en un lenguaje de código específico.", "El programa es anterior al algoritmo.", "El algoritmo solo lo entienden las computadoras.", "El programa es teórico y el algoritmo es práctico."], respuestaCorrecta: 1, explicacion: "El algoritmo es independiente de la máquina; el programa depende de la sintaxis de un lenguaje como Python o Java." },
  { id: 104, curso: "Algoritmia", pregunta: "¿Qué es un diagrama de flujo?", opciones: ["Un gráfico que representa la secuencia lógica de pasos de un algoritmo usando símbolos estandarizados.", "Un mapa de la red.", "Un tipo de variable.", "Un lenguaje de programación visual.", "Un error de sintaxis."], respuestaCorrecta: 0, explicacion: "Es una herramienta visual que facilita la comprensión, diseño y comunicación de un algoritmo antes de codificarlo." },
  { id: 105, curso: "Algoritmia", pregunta: "¿Qué representa un paralelogramo en un diagrama de flujo?", opciones: ["Un proceso o cálculo.", "Una decisión o condición.", "Una operación de entrada o salida de datos.", "El inicio o fin del algoritmo.", "Un conector entre páginas."], respuestaCorrecta: 2, explicacion: "Se usa universalmente para indicar cuando el algoritmo lee un dato (input) o muestra un resultado (output)." },
  { id: 106, curso: "Algoritmia", pregunta: "¿Qué representa un rombo en un diagrama de flujo?", opciones: ["Inicio/Fin.", "Entrada/Salida.", "Una decisión o condición que tiene caminos alternos (Sí/No).", "Un proceso matemático.", "Un comentario."], respuestaCorrecta: 2, explicacion: "El rombo evalúa una expresión booleana y dirige el flujo del algoritmo por una de sus dos (o más) salidas." },
  { id: 107, curso: "Algoritmia", pregunta: "¿Qué representa un rectángulo en un diagrama de flujo?", opciones: ["Una decisión.", "Un proceso, operación o asignación de valores.", "El inicio del programa.", "La entrada de datos.", "Un bucle."], respuestaCorrecta: 1, explicacion: "Indica una acción que transforma datos, como una suma, una asignación de variable o una llamada a una función." },
  { id: 108, curso: "Algoritmia", pregunta: "¿Qué es una variable?", opciones: ["Un valor que nunca cambia.", "Un espacio en la memoria del computador identificado por un nombre, que puede almacenar diferentes valores.", "Un tipo de cable.", "Un error de programación.", "Un comando de sistema."], respuestaCorrecta: 1, explicacion: "Es el contenedor fundamental de datos en programación, cuyo contenido puede variar durante la ejecución." },
  { id: 109, curso: "Algoritmia", pregunta: "¿Qué es una constante?", opciones: ["Un espacio de memoria cuyo valor se asigna una vez y no puede ser modificado durante la ejecución.", "Una variable que cambia constantemente.", "Un bucle infinito.", "Un tipo de dato booleano.", "Una función matemática."], respuestaCorrecta: 0, explicacion: "Se usa para valores fijos como PI o configuraciones que no deben alterarse por error en el código." },
  { id: 110, curso: "Algoritmia", pregunta: "¿Qué diferencia existe entre dato e información?", opciones: ["Son sinónimos.", "El dato es un hecho crudo sin contexto; la información es el dato procesado, organizado y con significado.", "La información es siempre numérica.", "El dato es más valioso que la información.", "No existe el concepto de dato."], respuestaCorrecta: 1, explicacion: "Ejemplo: '38' es un dato; '38 grados de temperatura corporal' es información." },
  { id: 111, curso: "Algoritmia", pregunta: "¿Qué tipos de datos básicos existen en programación?", opciones: ["Solo números.", "Enteros, flotantes (decimales), caracteres (char), cadenas (string) y booleanos.", "Solo texto.", "Imágenes y vídeos.", "Archivos y carpetas."], respuestaCorrecta: 1, explicacion: "Estos son los bloques de construcción primitivos que definen qué tipo de valor puede almacenar una variable." },
  { id: 112, curso: "Algoritmia", pregunta: "¿Qué es una expresión aritmética?", opciones: ["Una comparación de texto.", "Una combinación de operandos numéricos y operadores matemáticos (+, -, *, /) que produce un valor numérico.", "Una condición lógica.", "Un bucle.", "Una función."], respuestaCorrecta: 1, explicacion: "Ejemplo: '5 + 3 * 2' es una expresión aritmética que se evalúa a 11." },
  { id: 113, curso: "Algoritmia", pregunta: "¿Qué es una expresión lógica?", opciones: ["Una suma de números.", "Una expresión que se evalúa como verdadera (true) o falsa (false), usando operadores relacionales o lógicos.", "Una cadena de texto.", "Un tipo de variable.", "Un error de compilación."], respuestaCorrecta: 1, explicacion: "Ejemplo: 'A > B' o 'X == 5'. Son la base de las estructuras condicionales." },
  { id: 114, curso: "Algoritmia", pregunta: "¿Qué operadores relacionales conoces?", opciones: ["+, -, *, /", "==, !=, >, <, >=, <=", "AND, OR, NOT", "=, :=, <-", "++, --"], respuestaCorrecta: 1, explicacion: "Sirven para comparar dos valores y determinar la relación entre ellos, devolviendo un valor booleano." },
  { id: 115, curso: "Algoritmia", pregunta: "¿Qué operadores lógicos conoces?", opciones: ["+, -, *, /", "==, !=", "AND (Y), OR (O), NOT (NO)", ">, <", "++, --"], respuestaCorrecta: 2, explicacion: "Permiten combinar múltiples expresiones lógicas para formar condiciones más complejas." },
  { id: 116, curso: "Algoritmia", pregunta: "¿Cuál es la diferencia entre AND y OR?", opciones: ["No hay diferencia.", "AND requiere que todas las condiciones sean verdaderas; OR requiere que al menos una condición sea verdadera.", "OR es más estricto que AND.", "AND se usa solo con números.", "OR se usa solo con texto."], respuestaCorrecta: 1, explicacion: "AND es restrictivo (todo debe cumplirse), OR es inclusivo (con que uno se cumpla, el resultado es verdadero)." },
  { id: 117, curso: "Algoritmia", pregunta: "¿Qué es una estructura secuencial?", opciones: ["Una estructura que repite código.", "Aquella en la que una instrucción sigue a otra en orden lineal, de arriba hacia abajo, sin saltos.", "Una estructura que toma decisiones.", "Un tipo de variable.", "Un bucle infinito."], respuestaCorrecta: 1, explicacion: "Es la estructura más básica, donde el flujo de ejecución avanza paso a paso en el orden en que están escritas." },
  { id: 118, curso: "Algoritmia", pregunta: "¿Qué es una estructura condicional?", opciones: ["Una estructura que ejecuta código repetidamente.", "Una estructura que permite tomar decisiones, ejecutando diferentes bloques de código según si una condición es verdadera o falsa.", "Una estructura que declara variables.", "Una estructura que finaliza el programa.", "Una estructura que ordena datos."], respuestaCorrecta: 1, explicacion: "Representada por IF (si) y ELSE (sino), permite que el algoritmo se adapte a diferentes escenarios." },
  { id: 119, curso: "Algoritmia", pregunta: "¿Qué es una estructura repetitiva?", opciones: ["Una estructura que solo se ejecuta una vez.", "Un bucle o ciclo que permite ejecutar un bloque de código múltiples veces mientras se cumpla una condición.", "Una estructura de decisión.", "Una variable global.", "Una función."], respuestaCorrecta: 1, explicacion: "También llamadas bucles (FOR, WHILE), son esenciales para procesar colecciones de datos o repetir tareas sin reescribir código." },
  { id: 120, curso: "Algoritmia", pregunta: "¿Cuál es la diferencia entre IF simple e IF compuesto?", opciones: ["No hay diferencia.", "El IF simple solo ejecuta código si la condición es verdadera; el compuesto incluye un bloque ELSE para cuando la condición es falsa.", "El IF compuesto no usa condiciones.", "El IF simple es más lento.", "El IF compuesto solo funciona con números."], respuestaCorrecta: 1, explicacion: "El IF compuesto (if-else) maneja ambos caminos posibles de la decisión, mientras que el simple solo maneja el camino verdadero." },
  { id: 121, curso: "Algoritmia", pregunta: "¿Qué es una condición anidada?", opciones: ["Una condición fuera del programa.", "Una estructura condicional (IF) colocada dentro de otra estructura condicional.", "Una condición que siempre es falsa.", "Un bucle sin fin.", "Una variable sin tipo."], respuestaCorrecta: 1, explicacion: "Permite evaluar múltiples criterios de forma jerárquica, aunque un uso excesivo puede dificultar la legibilidad del código." },
  { id: 122, curso: "Algoritmia", pregunta: "¿Qué es un ciclo FOR?", opciones: ["Un ciclo que se repite indefinidamente.", "Un ciclo que se utiliza cuando se conoce de antemano la cantidad exacta de veces que se debe repetir el bloque de código.", "Un ciclo que nunca se ejecuta.", "Un ciclo que solo funciona con cadenas de texto.", "Una estructura condicional."], respuestaCorrecta: 1, explicacion: "Es ideal para iterar sobre un rango numérico o recorrer todos los elementos de una colección (array)." },
  { id: 123, curso: "Algoritmia", pregunta: "¿Qué es un ciclo WHILE?", opciones: ["Un ciclo que se ejecuta un número fijo de veces.", "Un ciclo que evalúa una condición antes de cada iteración y se repite mientras esa condición sea verdadera.", "Un ciclo que siempre se ejecuta al menos una vez.", "Un ciclo que no usa condiciones.", "Una estructura de decisión."], respuestaCorrecta: 1, explicacion: "Es útil cuando no se sabe de antemano cuántas iteraciones se necesitarán, dependiendo de un estado dinámico." },
  { id: 124, curso: "Algoritmia", pregunta: "¿Qué es un ciclo DO WHILE?", opciones: ["Un ciclo que no se ejecuta si la condición es falsa.", "Un ciclo que ejecuta el bloque de código al menos una vez y luego evalúa la condición para decidir si continúa.", "Un ciclo que solo funciona en Java.", "Un ciclo que no tiene condición de salida.", "Una variable de control."], respuestaCorrecta: 1, explicacion: "La condición se evalúa al final de la iteración, garantizando que el cuerpo del bucle se ejecute mínimo una vez." },
  { id: 125, curso: "Algoritmia", pregunta: "¿Cuándo es recomendable utilizar FOR en lugar de WHILE?", opciones: ["Cuando no se conoce el número de iteraciones.", "Cuando se conoce exactamente cuántas veces se debe repetir el ciclo o se itera sobre una colección.", "Cuando se necesita una condición compleja.", "Cuando se quiere un bucle infinito.", "Nunca, WHILE siempre es mejor."], respuestaCorrecta: 1, explicacion: "FOR es más legible y seguro cuando el número de repeticiones está acotado, ya que encapsula la inicialización, condición y actualización." },
  { id: 126, curso: "Algoritmia", pregunta: "¿Qué es un contador?", opciones: ["Una variable que acumula sumas de valores.", "Una variable que se incrementa o decrementa en una cantidad fija (usualmente 1) para llevar la cuenta de iteraciones o eventos.", "Una función matemática.", "Un tipo de bucle.", "Un operador lógico."], respuestaCorrecta: 1, explicacion: "Ejemplo: 'i = i + 1'. Se usa típicamente como variable de control en ciclos o para contar cuántas veces ocurre algo." },
  { id: 127, curso: "Algoritmia", pregunta: "¿Qué es un acumulador?", opciones: ["Una variable que cuenta iteraciones.", "Una variable que suma o acumula valores variables en cada iteración (ej. sumar precios).", "Un tipo de batería.", "Un operador de comparación.", "Una estructura de datos."], respuestaCorrecta: 1, explicacion: "A diferencia del contador (que suma 1), el acumulador suma cantidades variables: 'total = total + precio'." },
  { id: 128, curso: "Algoritmia", pregunta: "¿Qué es una bandera o variable booleana?", opciones: ["Una variable que almacena texto.", "Una variable que solo puede tomar dos valores (Verdadero/Falso) para indicar el estado de una condición o evento.", "Una variable numérica.", "Una constante.", "Un tipo de bucle."], respuestaCorrecta: 1, explicacion: "Se usa como señal (flag) para recordar si algo ocurrió (ej. 'encontrado = true') y controlar el flujo del programa." },
  { id: 129, curso: "Algoritmia", pregunta: "¿Qué es una función?", opciones: ["Un bloque de código que se ejecuta automáticamente.", "Un subprograma que realiza una tarea específica, puede recibir parámetros y devolver un valor.", "Una variable global.", "Un tipo de error.", "Un comentario en el código."], respuestaCorrecta: 1, explicacion: "Promueve la reutilización de código y la modularidad, permitiendo dividir problemas grandes en partes manejables." },
  { id: 130, curso: "Algoritmia", pregunta: "¿Qué diferencia existe entre función y procedimiento?", opciones: ["Son exactamente lo mismo.", "Una función devuelve un valor al lugar desde donde fue llamada; un procedimiento (o subrutina) solo ejecuta acciones sin devolver un valor.", "El procedimiento es más rápido.", "La función no puede recibir parámetros.", "El procedimiento solo existe en Python."], respuestaCorrecta: 1, explicacion: "En muchos lenguajes modernos esta distinción se difumina, pero conceptualmente, la función 'retorna' algo, el procedimiento no." },
  { id: 131, curso: "Algoritmia", pregunta: "¿Qué es un parámetro?", opciones: ["El valor real que se envía al llamar a una función.", "La variable declarada en la definición de la función que recibe el valor.", "Una variable global.", "El nombre de la función.", "El tipo de retorno."], respuestaCorrecta: 1, explicacion: "Es el 'placeholder' o nombre formal en la firma de la función que recibirá el dato cuando la función sea invocada." },
  { id: 132, curso: "Algoritmia", pregunta: "¿Qué es un argumento?", opciones: ["La variable en la definición de la función.", "El valor real y concreto que se pasa a la función cuando se la llama.", "Un error en la ejecución.", "El nombre del programa.", "Una estructura de control."], respuestaCorrecta: 1, explicacion: "Es el valor efectivo que sustituye al parámetro durante la ejecución de la función." },
  { id: 133, curso: "Algoritmia", pregunta: "¿Qué es el paso por valor?", opciones: ["Se pasa la dirección de memoria de la variable.", "Se pasa una copia del valor de la variable, por lo que las modificaciones dentro de la función no afectan a la variable original.", "La variable original se modifica.", "No se pasa ningún dato.", "Se pasa un objeto completo."], respuestaCorrecta: 1, explicacion: "Es el método más seguro para evitar efectos secundarios no deseados, ya que la función trabaja con una copia aislada." },
  { id: 134, curso: "Algoritmia", pregunta: "¿Qué es el paso por referencia?", opciones: ["Se pasa una copia del valor.", "Se pasa la dirección de memoria de la variable, por lo que las modificaciones dentro de la función afectan a la variable original.", "Se pasa un texto.", "No se puede modificar la variable.", "Es lo mismo que el paso por valor."], respuestaCorrecta: 1, explicacion: "Es más eficiente en memoria para estructuras grandes, pero requiere cuidado porque altera el dato original." },
  { id: 135, curso: "Algoritmia", pregunta: "¿Qué es un arreglo o vector?", opciones: ["Una variable que almacena un solo valor.", "Una estructura de datos que almacena una colección de elementos del mismo tipo en posiciones de memoria contiguas.", "Una función matemática.", "Un tipo de bucle.", "Un operador lógico."], respuestaCorrecta: 1, explicacion: "Permite agrupar múltiples datos bajo un mismo nombre, accediendo a ellos mediante un índice numérico." },
  { id: 136, curso: "Algoritmia", pregunta: "¿Cómo se accede a un elemento de un arreglo?", opciones: ["Usando el nombre del arreglo y un índice entre corchetes, ej: arreglo[0].", "Usando el nombre del arreglo y un punto.", "Usando una función especial.", "No se puede acceder a elementos individuales.", "Usando el operador +."], respuestaCorrecta: 0, explicacion: "El índice indica la posición del elemento. En la mayoría de lenguajes, el primer elemento está en el índice 0." },
  { id: 137, curso: "Algoritmia", pregunta: "¿Qué es una matriz?", opciones: ["Un arreglo de una sola dimensión.", "Un arreglo bidimensional (o multidimensional), como una tabla con filas y columnas.", "Una variable booleana.", "Un tipo de bucle.", "Una función recursiva."], respuestaCorrecta: 1, explicacion: "Se accede a sus elementos mediante dos índices: uno para la fila y otro para la columna, ej: matriz[fila][columna]." },
  { id: 138, curso: "Algoritmia", pregunta: "¿Cuál es la diferencia entre vector y matriz?", opciones: ["No hay diferencia.", "El vector es unidimensional (una lista), la matriz es bidimensional o superior (una tabla).", "El vector es más grande.", "La matriz solo almacena texto.", "El vector no usa índices."], respuestaCorrecta: 1, explicacion: "Un vector es un caso particular de matriz con una sola dimensión (N x 1)." },
  { id: 139, curso: "Algoritmia", pregunta: "¿Qué es una búsqueda secuencial?", opciones: ["Una búsqueda que divide el arreglo a la mitad.", "Un algoritmo que revisa cada elemento del arreglo uno por uno, desde el inicio hasta el final, hasta encontrar el objetivo.", "Una búsqueda que solo funciona en matrices.", "Una búsqueda que ordena los datos.", "Una búsqueda aleatoria."], respuestaCorrecta: 1, explicacion: "Es simple de implementar pero ineficiente para conjuntos de datos grandes, ya que en el peor caso revisa todos los elementos." },
  { id: 140, curso: "Algoritmia", pregunta: "¿Qué es una búsqueda binaria?", opciones: ["Una búsqueda que revisa elemento por elemento.", "Un algoritmo eficiente que divide repetidamente el intervalo de búsqueda a la mitad, descartando la mitad donde no está el objetivo.", "Una búsqueda que solo funciona en arreglos desordenados.", "Una búsqueda que usa fuerza bruta.", "Una búsqueda en bases de datos."], respuestaCorrecta: 1, explicacion: "Es mucho más rápida que la secuencial, pero tiene un requisito estricto sobre los datos." },
  { id: 141, curso: "Algoritmia", pregunta: "¿Qué requisito necesita una búsqueda binaria para funcionar correctamente?", opciones: ["Que el arreglo esté vacío.", "Que el arreglo esté previamente ordenado.", "Que el arreglo tenga solo números negativos.", "Que el arreglo sea bidimensional.", "Que el arreglo tenga un tamaño impar."], respuestaCorrecta: 1, explicacion: "El algoritmo depende de la propiedad de orden para poder descartar la mitad del espacio de búsqueda de forma segura." },
  { id: 142, curso: "Algoritmia", pregunta: "¿Qué es un algoritmo de ordenamiento?", opciones: ["Un algoritmo que busca un elemento.", "Un algoritmo que reorganiza los elementos de una colección en un orden específico (ascendente o descendente).", "Un algoritmo que elimina duplicados.", "Un algoritmo que comprime datos.", "Un algoritmo que encripta información."], respuestaCorrecta: 1, explicacion: "Es una operación fundamental en ciencias de la computación para facilitar búsquedas y presentaciones de datos." },
  { id: 143, curso: "Algoritmia", pregunta: "¿Cómo funciona el método Burbuja?", opciones: ["Ordena dividiendo y venciendo.", "Compara pares de elementos adyacentes y los intercambia si están en el orden incorrecto, repitiendo hasta que no haya intercambios.", "Selecciona el menor y lo pone al inicio.", "Inserta cada elemento en su lugar correcto.", "Usa una pila."], respuestaCorrecta: 1, explicacion: "Es fácil de entender pero muy ineficiente (O(n²)) para listas grandes, ya que 'burbujea' los elementos mayores al final." },
  { id: 144, curso: "Algoritmia", pregunta: "¿Cómo funciona el método Selección?", opciones: ["Intercambia adyacentes.", "Busca repetidamente el elemento mínimo del segmento no ordenado y lo intercambia con el primer elemento de ese segmento.", "Divide el arreglo en dos.", "Usa recursión.", "Ordena de atrás hacia adelante."], respuestaCorrecta: 1, explicacion: "Realiza menos intercambios que la burbuja, pero su complejidad temporal sigue siendo O(n²) en todos los casos." },
  { id: 145, curso: "Algoritmia", pregunta: "¿Cómo funciona el método Inserción?", opciones: ["Construye el arreglo ordenado de a un elemento a la vez, insertando cada nuevo elemento en su posición correcta dentro de la parte ya ordenada.", "Divide el arreglo a la mitad.", "Usa un pivote.", "Es un algoritmo aleatorio.", "Solo funciona con números primos."], respuestaCorrecta: 0, explicacion: "Es muy eficiente para listas pequeñas o que ya están casi ordenadas (complejidad cercana a O(n) en el mejor caso)." },
  { id: 146, curso: "Algoritmia", pregunta: "¿Qué significa complejidad temporal?", opciones: ["El tiempo exacto en segundos que tarda un programa.", "Una medida teórica de cómo crece el tiempo de ejecución de un algoritmo a medida que aumenta el tamaño de la entrada (n).", "La cantidad de memoria usada.", "El número de líneas de código.", "La velocidad del procesador."], respuestaCorrecta: 1, explicacion: "No mide segundos reales, sino la tasa de crecimiento del número de operaciones, independientemente del hardware." },
  { id: 147, curso: "Algoritmia", pregunta: "¿Qué significa complejidad espacial?", opciones: ["El tamaño del monitor.", "Una medida de la cantidad de memoria adicional que necesita un algoritmo en función del tamaño de la entrada.", "El tiempo de ejecución.", "El número de variables.", "La velocidad de internet."], respuestaCorrecta: 1, explicacion: "Evalúa la eficiencia del uso de la memoria RAM, incluyendo el espacio para variables auxiliares y estructuras de datos." },
  { id: 148, curso: "Algoritmia", pregunta: "¿Qué representa la notación Big O?", opciones: ["El mejor caso de un algoritmo.", "El límite superior o peor caso de crecimiento de la complejidad de un algoritmo.", "El caso promedio.", "Un tipo de variable.", "Un error de compilación."], respuestaCorrecta: 1, explicacion: "Proporciona una cota superior asintótica, garantizando que el algoritmo no será peor que ese crecimiento (ej. O(n), O(n²))." },
  { id: 149, curso: "Algoritmia", pregunta: "¿Qué complejidad tiene una búsqueda lineal?", opciones: ["O(1)", "O(log n)", "O(n)", "O(n²)", "O(n log n)"], respuestaCorrecta: 2, explicacion: "En el peor caso, debe recorrer los 'n' elementos del arreglo uno por uno, por lo que el tiempo crece linealmente con el tamaño." },
  { id: 150, curso: "Algoritmia", pregunta: "¿Qué complejidad tiene una búsqueda binaria?", opciones: ["O(1)", "O(log n)", "O(n)", "O(n²)", "O(n!)"], respuestaCorrecta: 1, explicacion: "Al dividir el espacio de búsqueda a la mitad en cada paso, el número de operaciones crece logarítmicamente, siendo muy eficiente." },
  { id: 151, curso: "Red Hat System Administration I", pregunta: "¿Qué es systemd?", opciones: ["Un editor de texto.", "El sistema de inicio y administrador de servicios predeterminado en Red Hat.", "Un protocolo de red.", "Un gestor de paquetes.", "Un firewall."], respuestaCorrecta: 1, explicacion: "systemd es el init system que gestiona el arranque del sistema y los servicios en segundo plano." },
  { id: 152, curso: "Red Hat System Administration I", pregunta: "¿Qué comando permite gestionar servicios en sistemas modernos de Red Hat?", opciones: ["service", "init.d", "systemctl", "chkconfig", "manage"], respuestaCorrecta: 2, explicacion: "systemctl es la herramienta principal para interactuar con systemd." },
  { id: 153, curso: "Red Hat System Administration I", pregunta: "¿Cómo iniciar un servicio usando systemctl?", opciones: ["systemctl start nombre_servicio", "systemctl begin nombre_servicio", "start servicio nombre", "service nombre start", "init start nombre"], respuestaCorrecta: 0, explicacion: "La sintaxis correcta es 'systemctl start' seguida del nombre de la unidad del servicio." },
  { id: 154, curso: "Red Hat System Administration I", pregunta: "¿Cómo detener un servicio usando systemctl?", opciones: ["systemctl stop nombre_servicio", "systemctl end nombre_servicio", "kill servicio", "halt nombre_servicio", "systemctl down nombre_servicio"], respuestaCorrecta: 0, explicacion: "'systemctl stop' termina la ejecución del servicio de manera controlada." },
  { id: 155, curso: "Red Hat System Administration I", pregunta: "¿Qué hace systemctl enable?", opciones: ["Inicia el servicio inmediatamente.", "Configura el servicio para que se inicie automáticamente al arrancar el sistema.", "Deshabilita el servicio.", "Reinicia el servicio.", "Muestra el estado del servicio."], respuestaCorrecta: 1, explicacion: "Crea los enlaces simbólicos necesarios para que el servicio se inicie en el target por defecto." },
  { id: 156, curso: "Red Hat System Administration I", pregunta: "¿Cómo visualizar los logs del sistema usando journalctl?", opciones: ["cat /var/log/messages", "journalctl", "logread", "systemctl logs", "dmesg -all"], respuestaCorrecta: 1, explicacion: "journalctl consulta el diario de systemd, que centraliza los logs del kernel y los servicios." },
  { id: 157, curso: "Red Hat System Administration I", pregunta: "¿Qué es un paquete RPM?", opciones: ["Un archivo de configuración.", "Red Hat Package Manager, formato estándar de empaquetado de software.", "Un tipo de sistema de archivos.", "Un protocolo de enrutamiento.", "Una herramienta de monitoreo."], respuestaCorrecta: 1, explicacion: "RPM es el formato de archivo (.rpm) y la herramienta de bajo nivel para instalar software en Red Hat." },
  { id: 158, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia existe entre RPM y DNF?", opciones: ["Son lo mismo.", "RPM instala paquetes locales sin resolver dependencias; DNF resuelve dependencias automáticamente desde repositorios.", "DNF es solo para Ubuntu.", "RPM es más moderno que DNF.", "DNF no puede instalar paquetes."], respuestaCorrecta: 1, explicacion: "DNF (Dandified YUM) es el gestor de alto nivel que usa RPM como backend, pero añade resolución inteligente de dependencias." },
  { id: 159, curso: "Red Hat System Administration I", pregunta: "¿Qué comando instala paquetes en Red Hat?", opciones: ["apt-get install", "yum install o dnf install", "pkg add", "installpkg", "rpm -add"], respuestaCorrecta: 1, explicacion: "dnf install (o yum install en versiones antiguas) es el método recomendado para instalar software." },
  { id: 160, curso: "Red Hat System Administration I", pregunta: "¿Qué son los repositorios de software?", opciones: ["Carpetas locales del usuario.", "Servidores remotos que almacenan paquetes de software y sus metadatos.", "Archivos de texto plano.", "Drivers de hardware.", "Reglas de firewall."], respuestaCorrecta: 1, explicacion: "Son fuentes configuradas en /etc/yum.repos.d/ de donde DNF descarga los paquetes." },
  { id: 161, curso: "Red Hat System Administration I", pregunta: "¿Qué es el archivo /etc/passwd?", opciones: ["Almacena las contraseñas encriptadas.", "Contiene información básica de las cuentas de usuario (nombre, UID, GID, shell).", "Configura la red.", "Define los montajes de disco.", "Registra los intentos de login fallidos."], respuestaCorrecta: 1, explicacion: "Es un archivo legible por todos que mapea nombres de usuario a sus atributos básicos." },
  { id: 162, curso: "Red Hat System Administration I", pregunta: "¿Qué información almacena /etc/shadow?", opciones: ["La configuración del shell.", "Las contraseñas encriptadas y la política de expiración de las cuentas.", "El historial de comandos.", "Las claves SSH públicas.", "Los permisos de los archivos."], respuestaCorrecta: 1, explicacion: "Solo legible por root, protege las contraseñas de accesos no autorizados." },
  { id: 163, curso: "Red Hat System Administration I", pregunta: "¿Qué comando crea usuarios nuevos?", opciones: ["adduser o useradd", "newuser", "mkuser", "createuser", "usermake"], respuestaCorrecta: 0, explicacion: "useradd es el comando de bajo nivel, y adduser suele ser un script amigable que lo envuelve." },
  { id: 164, curso: "Red Hat System Administration I", pregunta: "¿Qué comando cambia la contraseña de un usuario?", opciones: ["chpass", "passwd", "password", "shadow", "pwd"], respuestaCorrecta: 1, explicacion: "El comando passwd permite a los usuarios cambiar su propia contraseña, o a root cambiar la de cualquier usuario." },
  { id: 165, curso: "Red Hat System Administration I", pregunta: "¿Cómo agregarías un usuario a un grupo?", opciones: ["usermod -aG grupo usuario", "adduser grupo usuario", "groupadd usuario", "chgrp usuario grupo", "useradd -g grupo"], respuestaCorrecta: 0, explicacion: "usermod -aG (append group) añade el usuario al grupo secundario sin eliminar sus grupos actuales." },
  { id: 166, curso: "Red Hat System Administration I", pregunta: "¿Cuál es la función del directorio /etc?", opciones: ["Almacenar archivos temporales.", "Contener archivos de configuración del sistema y servicios.", "Almacenar los directorios home.", "Montar dispositivos externos.", "Guardar logs del sistema."], respuestaCorrecta: 1, explicacion: "Es el directorio central de configuración en Linux (ej. /etc/fstab, /etc/passwd)." },
  { id: 167, curso: "Red Hat System Administration I", pregunta: "¿Cuál es la función del directorio /var?", opciones: ["Archivos binarios ejecutables.", "Archivos variables como logs, colas de impresión y caché.", "Archivos del kernel.", "Dispositivos de hardware.", "Puntos de montaje."], respuestaCorrecta: 1, explicacion: "/var (variable) contiene datos que cambian de tamaño frecuentemente durante la operación normal del sistema." },
  { id: 168, curso: "Red Hat System Administration I", pregunta: "¿Qué es una partición?", opciones: ["Un archivo comprimido.", "Una división lógica de un disco duro que el sistema operativo trata como un disco independiente.", "Un tipo de memoria RAM.", "Un protocolo de red.", "Un servicio de systemd."], respuestaCorrecta: 1, explicacion: "Permite organizar el almacenamiento y separar, por ejemplo, el sistema operativo de los datos del usuario." },
  { id: 169, curso: "Red Hat System Administration I", pregunta: "¿Qué hace el comando mount?", opciones: ["Desconecta un dispositivo.", "Asocia un sistema de archivos de un dispositivo a un directorio (punto de montaje) del árbol de directorios.", "Formatea un disco.", "Crea una partición.", "Revisa errores de disco."], respuestaCorrecta: 1, explicacion: "Hace que el contenido del dispositivo sea accesible en la ruta especificada." },
  { id: 170, curso: "Red Hat System Administration I", pregunta: "¿Para qué sirve el archivo /etc/fstab?", opciones: ["Configurar el firewall.", "Definir los sistemas de archivos que se deben montar automáticamente al iniciar el sistema.", "Almacenar contraseñas.", "Configurar la red.", "Definir usuarios."], respuestaCorrecta: 1, explicacion: "File System Table contiene la información estática sobre los discos y particiones." },
  { id: 171, curso: "Red Hat System Administration I", pregunta: "¿Qué hace el comando ping?", opciones: ["Muestra la ruta de los paquetes.", "Prueba la conectividad de red enviando paquetes ICMP Echo Request.", "Escanea puertos abiertos.", "Muestra la tabla ARP.", "Configura la dirección IP."], respuestaCorrecta: 1, explicacion: "Es la herramienta básica de diagnóstico para verificar si un host es alcanzable." },
  { id: 172, curso: "Red Hat System Administration I", pregunta: "¿Qué puerto utiliza SSH por defecto?", opciones: ["21", "22", "23", "80", "443"], respuestaCorrecta: 1, explicacion: "El puerto 22 es el estándar asignado para el protocolo Secure Shell." },
  { id: 173, curso: "Red Hat System Administration I", pregunta: "¿Qué ventajas ofrece SSH respecto a Telnet?", opciones: ["Es más rápido.", "Cifra toda la comunicación, incluyendo contraseñas, evitando la interceptación.", "No requiere autenticación.", "Usa menos ancho de banda.", "Viene instalado por defecto en Windows."], respuestaCorrecta: 1, explicacion: "Telnet envía datos en texto plano, mientras que SSH usa criptografía para garantizar la confidencialidad." },
  { id: 174, curso: "Red Hat System Administration I", pregunta: "¿Qué es un firewall?", opciones: ["Un antivirus.", "Un sistema de seguridad de red que monitorea y controla el tráfico entrante y saliente según reglas.", "Un tipo de cable.", "Un servidor web.", "Un gestor de paquetes."], respuestaCorrecta: 1, explicacion: "Actúa como una barrera entre una red confiable y una no confiable." },
  { id: 175, curso: "Red Hat System Administration I", pregunta: "¿Qué herramienta utiliza Red Hat para administrar firewall?", opciones: ["iptables solamente", "firewalld", "ufw", "Windows Firewall", "SELinux"], respuestaCorrecta: 1, explicacion: "firewalld es el demonio de firewall dinámico predeterminado en Red Hat, que gestiona netfilter/iptables." },
  { id: 176, curso: "CCNA M1", pregunta: "¿Qué es una red informática?", opciones: ["Un solo computador.", "Dos o más computadoras conectadas para compartir recursos e información.", "Un cable de fibra óptica.", "Un sistema operativo.", "Un programa de software."], respuestaCorrecta: 1, explicacion: "La interconexión permite la comunicación y el intercambio de datos entre dispositivos." },
  { id: 177, curso: "CCNA M1", pregunta: "¿Cuál es la diferencia entre LAN y WAN?", opciones: ["No hay diferencia.", "LAN cubre un área geográfica pequeña (ej. edificio), WAN cubre áreas extensas (ej. países).", "WAN es más rápida que LAN.", "LAN usa satélites, WAN usa cables.", "WAN es solo para redes inalámbricas."], respuestaCorrecta: 1, explicacion: "LAN (Local Area Network) es local; WAN (Wide Area Network) interconecta LANs a larga distancia." },
  { id: 178, curso: "CCNA M1", pregunta: "¿Qué función cumple una NIC (tarjeta de red)?", opciones: ["Procesar gráficos.", "Conectar físicamente un dispositivo a la red y proporcionar una dirección MAC.", "Almacenar datos.", "Enfriar el procesador.", "Gestionar la energía."], respuestaCorrecta: 1, explicacion: "Network Interface Card es el hardware que permite la comunicación en la red, operando en la Capa 2." },
  { id: 179, curso: "CCNA M1", pregunta: "¿Cuál es la diferencia entre hub y switch?", opciones: ["Son idénticos.", "El hub reenvía datos a todos los puertos (broadcast); el switch envía datos solo al puerto de destino (MAC).", "El switch es más antiguo.", "El hub opera en Capa 3.", "El switch no usa direcciones MAC."], respuestaCorrecta: 1, explicacion: "El switch es inteligente y crea dominios de colisión separados por puerto, a diferencia del hub." },
  { id: 180, curso: "CCNA M1", pregunta: "¿Cuántos bits tiene una dirección MAC?", opciones: ["32 bits", "48 bits", "64 bits", "128 bits", "16 bits"], respuestaCorrecta: 1, explicacion: "Una dirección MAC tiene 48 bits, representados habitualmente como 6 grupos de 2 dígitos hexadecimales." },
  { id: 181, curso: "CCNA M1", pregunta: "¿Cuántos bits tiene una dirección IPv4?", opciones: ["32 bits", "48 bits", "64 bits", "128 bits", "8 bits"], respuestaCorrecta: 0, explicacion: "IPv4 usa 32 bits, divididos en 4 octetos (ej. 192.168.1.1)." },
  { id: 182, curso: "CCNA M1", pregunta: "¿Qué función cumple ARP?", opciones: ["Resuelve nombres de dominio a IP.", "Resuelve direcciones IP a direcciones MAC.", "Asigna direcciones IP automáticamente.", "Enruta paquetes entre redes.", "Cifra el tráfico."], respuestaCorrecta: 1, explicacion: "Address Resolution Protocol mapea una dirección IP conocida a una dirección MAC desconocida en la LAN." },
  { id: 183, curso: "CCNA M1", pregunta: "¿Qué función cumple DHCP?", opciones: ["Resuelve nombres a IP.", "Asigna automáticamente direcciones IP y configuración de red a los clientes.", "Encripta contraseñas.", "Filtra paquetes.", "Gestiona el enrutamiento."], respuestaCorrecta: 1, explicacion: "Dynamic Host Configuration Protocol automatiza la configuración de red, evitando conflictos manuales." },
  { id: 184, curso: "CCNA M1", pregunta: "¿Qué es encapsulación?", opciones: ["Borrar datos.", "El proceso de agregar encabezados (y a veces tráilers) a los datos a medida que bajan por el modelo OSI.", "Comprimir archivos.", "Encriptar el tráfico.", "Dividir una red en VLANs."], respuestaCorrecta: 1, explicacion: "Cada capa agrega su propia información de control (PDU) antes de pasar los datos a la capa inferior." },
  { id: 185, curso: "CCNA M2", pregunta: "¿Qué es una VLAN?", opciones: ["Un tipo de cable.", "Virtual LAN, una red lógica creada dentro de un switch físico para segmentar el tráfico.", "Un protocolo de enrutamiento.", "Una dirección IP.", "Un firewall."], respuestaCorrecta: 1, explicacion: "Permite agrupar dispositivos lógicamente, independientemente de su ubicación física, mejorando la seguridad y el rendimiento." },
  { id: 186, curso: "CCNA M2", pregunta: "¿Qué es un puerto de acceso?", opciones: ["Un puerto que conecta dos switches.", "Un puerto de switch configurado para pertenecer a una sola VLAN, típicamente conectado a un endpoint.", "Un puerto de alta velocidad.", "Un puerto de consola.", "Un puerto que transporta múltiples VLANs."], respuestaCorrecta: 1, explicacion: "Los puertos de acceso llevan tráfico de una única VLAN sin etiquetar (untagged)." },
  { id: 187, curso: "CCNA M2", pregunta: "¿Qué es un puerto troncal (trunk)?", opciones: ["Un puerto para conectar PCs.", "Un puerto que transporta tráfico de múltiples VLANs entre switches, usando etiquetado.", "Un puerto deshabilitado.", "Un puerto de administración.", "Un puerto de fibra óptica exclusivo."], respuestaCorrecta: 1, explicacion: "Utiliza protocolos como 802.1Q para agregar una etiqueta (tag) que identifica a qué VLAN pertenece cada trama." },
  { id: 188, curso: "CCNA M2", pregunta: "¿Qué hace el estándar IEEE 802.1Q?", opciones: ["Define el enrutamiento OSPF.", "Es el protocolo estándar para etiquetado de tramas en enlaces troncales (VLAN tagging).", "Define la seguridad Wi-Fi.", "Es un protocolo de descubrimiento de vecinos.", "Define la dirección MAC."], respuestaCorrecta: 1, explicacion: "Inserta un campo de 4 bytes en la trama Ethernet para identificar la VLAN." },
  { id: 189, curso: "CCNA M2", pregunta: "¿Qué es STP (Spanning Tree Protocol)?", opciones: ["Un protocolo para encriptar datos.", "Un protocolo de Capa 2 que previene bucles de conmutación en topologías con enlaces redundantes.", "Un protocolo de enrutamiento.", "Un protocolo para asignar IPs.", "Un protocolo de voz sobre IP."], respuestaCorrecta: 1, explicacion: "STP bloquea lógicamente ciertos puertos para garantizar que solo haya un camino activo entre dos switches." },
  { id: 190, curso: "CCNA M2", pregunta: "¿Qué problema evita STP?", opciones: ["Ataques de phishing.", "Bucles de Capa 2 que causan tormentas de broadcast y tablas MAC inestables.", "Fallas de hardware.", "Pérdida de energía.", "Configuraciones incorrectas de IP."], respuestaCorrecta: 1, explicacion: "Sin STP, las tramas de broadcast circularían infinitamente en una topología con bucles, colapsando la red." },
  { id: 191, curso: "CCNA M2", pregunta: "¿Qué es PortFast?", opciones: ["Una función de STP que hace que un puerto de acceso pase inmediatamente al estado de forwarding, omitiendo la escucha y aprendizaje.", "Un protocolo de enrutamiento rápido.", "Una marca de switches.", "Un tipo de cable.", "Una función de seguridad."], respuestaCorrecta: 0, explicacion: "Se usa en puertos conectados a PCs o servidores para que la red esté disponible inmediatamente al encender el equipo." },
  { id: 192, curso: "CCNA M2", pregunta: "¿Qué es EtherChannel?", opciones: ["Un tipo de VLAN.", "La agrupación de múltiples enlaces físicos entre dos switches en un único enlace lógico para aumentar el ancho de banda.", "Un protocolo de seguridad.", "Un tipo de cable de fibra.", "Una dirección IP."], respuestaCorrecta: 1, explicacion: "También conocido como PortChannel, proporciona redundancia y balanceo de carga." },
  { id: 193, curso: "CCNA M2", pregunta: "¿Qué es una SVI (Switch Virtual Interface)?", opciones: ["Un puerto físico.", "Una interfaz de VLAN virtual que permite al switch ser gestionado remotamente o realizar enrutamiento inter-VLAN.", "Un cable de consola.", "Un tipo de memoria.", "Un protocolo de enrutamiento."], respuestaCorrecta: 1, explicacion: "Se le asigna una dirección IP a la VLAN para que el switch tenga presencia en la Capa 3." },
  { id: 194, curso: "CCNA M2", pregunta: "¿Qué es seguridad de puertos (Port Security)?", opciones: ["Una contraseña para el switch.", "Una característica que restringe las direcciones MAC permitidas en un puerto de acceso para prevenir accesos no autorizados.", "Un firewall.", "Un protocolo de encriptación.", "Un tipo de VLAN."], respuestaCorrecta: 1, explicacion: "Puede limitar el número de MACs o especificar MACs estáticas, protegiendo contra la conexión de dispositivos no autorizados." },
  { id: 195, curso: "CCNA M3", pregunta: "¿Qué es una ruta flotante?", opciones: ["Una ruta que cambia constantemente.", "Una ruta estática de respaldo con una distancia administrativa mayor que la ruta principal, que solo se usa si la principal falla.", "Una ruta dinámica.", "Una ruta sin máscara.", "Una ruta hacia Internet."], respuestaCorrecta: 1, explicacion: "Al tener una DA mayor, no se instala en la tabla de enrutamiento a menos que la ruta primaria (con menor DA) desaparezca." },
  { id: 196, curso: "CCNA M3", pregunta: "¿Qué es CIDR?", opciones: ["Classless Inter-Domain Routing, un método para asignar direcciones IP y enrutar que elimina las clases tradicionales (A, B, C).", "Un protocolo de seguridad.", "Un tipo de cable.", "Un software de monitoreo.", "Una marca de routers."], respuestaCorrecta: 0, explicacion: "Permite una asignación más flexible y eficiente de direcciones IP usando máscaras de longitud variable." },
  { id: 197, curso: "CCNA M3", pregunta: "¿Qué significa VLSM?", opciones: ["Variable Length Subnet Mask, la capacidad de usar diferentes máscaras de subred dentro de la misma red de clase.", "Virtual LAN Subnet Manager.", "Very Large System Memory.", "Variable Link State Metric.", "Virtual Local Switching Method."], respuestaCorrecta: 0, explicacion: "Permite subdividir una subred en subredes más pequeñas de diferentes tamaños, optimizando el uso de direcciones IP." },
  { id: 198, curso: "CCNA M3", pregunta: "¿Qué es una red supernet?", opciones: ["Una red más pequeña.", "La combinación de múltiples redes contiguas en una sola ruta resumen con una máscara más corta.", "Una red inalámbrica.", "Una red sin router.", "Una red de área local."], respuestaCorrecta: 1, explicacion: "Es lo opuesto al subnetting; agrupa redes para reducir el tamaño de las tablas de enrutamiento." },
  { id: 199, curso: "CCNA M3", pregunta: "¿Qué es un protocolo de estado de enlace?", opciones: ["Un protocolo que solo envía su tabla de enrutamiento.", "Un protocolo donde cada router construye un mapa completo de la red (LSDB) y calcula la mejor ruta independientemente.", "Un protocolo de capa 2.", "Un protocolo propietario de Microsoft.", "Un protocolo que no usa métricas."], respuestaCorrecta: 1, explicacion: "OSPF e IS-IS son ejemplos; convergen rápidamente y son escalables." },
  { id: 200, curso: "CCNA M3", pregunta: "¿Qué es un LSA en OSPF?", opciones: ["Link State Advertisement, un paquete que contiene información sobre el estado de los enlaces de un router.", "Local System Address.", "Link State Algorithm.", "Logical Subnet Area.", "Longest Specific Address."], respuestaCorrecta: 0, explicacion: "Los routers intercambian LSAs para construir la Base de Datos de Estado de Enlace (LSDB)." },
  { id: 201, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es HTML5?", opciones: ["Un lenguaje de programación.", "La última versión estándar de HTML, que introduce nuevas etiquetas semánticas, soporte multimedia nativo y APIs.", "Un framework de JavaScript.", "Un sistema de bases de datos.", "Un protocolo de red."], respuestaCorrecta: 1, explicacion: "HTML5 modernizó la web, eliminando la dependencia de plugins como Flash para vídeo y audio." },
  { id: 202, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué son las etiquetas semánticas?", opciones: ["Etiquetas que solo dan estilo.", "Etiquetas que describen el significado del contenido (ej. <header>, <article>, <footer>), mejorando la accesibilidad y el SEO.", "Etiquetas obsoletas.", "Etiquetas de JavaScript.", "Etiquetas de comentarios."], respuestaCorrecta: 1, explicacion: "Ayudan a los motores de búsqueda y lectores de pantalla a entender la estructura de la página." },
  { id: 203, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Para qué sirve la etiqueta <nav>?", opciones: ["Para crear una imagen.", "Para definir un bloque de enlaces de navegación principales.", "Para el pie de página.", "Para un artículo independiente.", "Para metadata."], respuestaCorrecta: 1, explicacion: "Indica que el contenido dentro de ella es un menú o conjunto de enlaces de navegación." },
  { id: 204, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es Responsive Design?", opciones: ["Un diseño que solo funciona en PC.", "Una técnica de diseño web que hace que la página se adapte automáticamente a diferentes tamaños de pantalla (móvil, tablet, escritorio).", "Un diseño que responde a comandos de voz.", "Un tipo de base de datos.", "Un lenguaje de programación."], respuestaCorrecta: 1, explicacion: "Utiliza CSS (como media queries y flexbox/grid) para garantizar una experiencia de usuario óptima en cualquier dispositivo." },
  { id: 205, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué son las Media Queries?", opciones: ["Consultas a una base de datos.", "Reglas CSS que aplican estilos condicionalmente según las características del dispositivo (ej. ancho de pantalla).", "Etiquetas HTML.", "Funciones de JavaScript.", "Protocolos de red."], respuestaCorrecta: 1, explicacion: "Son la base del diseño responsivo, permitiendo cambiar el layout según el viewport." },
  { id: 206, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una API?", opciones: ["Un tipo de archivo.", "Application Programming Interface, un conjunto de reglas que permite que dos aplicaciones de software se comuniquen entre sí.", "Un lenguaje de marcado.", "Un sistema operativo.", "Un navegador web."], respuestaCorrecta: 1, explicacion: "Las APIs web permiten que el frontend solicite datos a un servidor (backend) de forma estructurada." },
  { id: 207, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es JSON?", opciones: ["Un lenguaje de programación.", "JavaScript Object Notation, un formato ligero de intercambio de datos, fácil de leer para humanos y máquinas.", "Una hoja de estilos.", "Un sistema de gestión de versiones.", "Un servidor web."], respuestaCorrecta: 1, explicacion: "Es el estándar actual para enviar y recibir datos en APIs web, reemplazando en gran medida a XML." },
  { id: 208, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Cuál es la diferencia entre una petición GET y POST?", opciones: ["No hay diferencia.", "GET solicita datos y los envía en la URL; POST envía datos al servidor para ser procesados, ocultándolos en el cuerpo de la petición.", "POST es solo para leer datos.", "GET es más seguro que POST.", "POST no puede enviar archivos."], respuestaCorrecta: 1, explicacion: "GET es idempotente y para recuperación; POST es para crear o actualizar recursos, permitiendo mayor volumen y seguridad de datos." },
  { id: 209, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace document.querySelector()?", opciones: ["Crea un nuevo elemento HTML.", "Devuelve el primer elemento del documento que coincide con un selector CSS especificado.", "Elimina un elemento.", "Recarga la página.", "Cambia el título de la página."], respuestaCorrecta: 1, explicacion: "Es un método versátil del DOM que permite seleccionar elementos por etiqueta, clase (.clase) o id (#id)." },
  { id: 210, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre innerHTML y textContent?", opciones: ["Son idénticos.", "innerHTML interpreta el contenido como HTML (ejecutando etiquetas), mientras que textContent solo maneja texto plano, siendo más seguro.", "textContent es más rápido pero obsoleto.", "innerHTML solo lee, no escribe.", "textContent permite inyectar scripts."], respuestaCorrecta: 1, explicacion: "Usar textContent previene ataques XSS (Cross-Site Scripting) al no evaluar el código HTML inyectado." },
  { id: 211, curso: "Algoritmia", pregunta: "¿Qué es un ciclo anidado?", opciones: ["Un ciclo que no tiene fin.", "Un ciclo (bucle) colocado dentro de otro ciclo.", "Una función que se llama a sí misma.", "Una variable global.", "Una estructura condicional."], respuestaCorrecta: 1, explicacion: "Se usa comúnmente para recorrer estructuras bidimensionales como matrices, donde el ciclo interno se ejecuta completamente por cada iteración del externo." },
  { id: 212, curso: "Algoritmia", pregunta: "¿Qué es la recursión?", opciones: ["Un bucle infinito.", "Una técnica donde una función se llama a sí misma para resolver un problema dividiéndolo en subproblemas más pequeños.", "Un tipo de variable.", "Un error de sintaxis.", "Un método de ordenamiento."], respuestaCorrecta: 1, explicacion: "Requiere un caso base para detenerse y un paso recursivo que se acerque a ese caso base." },
  { id: 213, curso: "Algoritmia", pregunta: "¿Qué es un caso base en recursión?", opciones: ["La primera vez que se llama la función.", "La condición que detiene las llamadas recursivas, evitando un bucle infinito.", "El valor de retorno.", "El parámetro de entrada.", "El nombre de la función."], respuestaCorrecta: 1, explicacion: "Sin un caso base, la función seguiría llamándose hasta agotar la memoria de la pila (Stack Overflow)." },
  { id: 214, curso: "Algoritmia", pregunta: "¿Qué es una pila (Stack) en estructuras de datos?", opciones: ["Una estructura FIFO (First In, First Out).", "Una estructura LIFO (Last In, First Out) donde el último elemento en entrar es el primero en salir.", "Un tipo de árbol.", "Una tabla hash.", "Un gráfico."], respuestaCorrecta: 1, explicacion: "Las operaciones principales son push (apilar) y pop (desapilar). Se usa en la gestión de llamadas a funciones." },
  { id: 215, curso: "Algoritmia", pregunta: "¿Qué es una cola (Queue)?", opciones: ["Una estructura LIFO.", "Una estructura FIFO (First In, First Out), como una fila de personas.", "Un arreglo bidimensional.", "Un puntero.", "Una variable booleana."], respuestaCorrecta: 1, explicacion: "Las operaciones principales son enqueue (encolar) y dequeue (desencolar)." },
  { id: 216, curso: "Algoritmia", pregunta: "¿Qué complejidad tiene el algoritmo de ordenamiento Burbuja en el peor caso?", opciones: ["O(1)", "O(log n)", "O(n)", "O(n²)", "O(n log n)"], respuestaCorrecta: 3, explicacion: "Debido a sus dos bucles anidados que recorren el arreglo, su rendimiento se degrada cuadráticamente con el tamaño de los datos." },
  { id: 217, curso: "Algoritmia", pregunta: "¿Qué algoritmo de ordenamiento es generalmente más eficiente para grandes conjuntos de datos?", opciones: ["Burbuja", "Inserción", "Selección", "Merge Sort (Ordenamiento por Mezcla)", "Todos son iguales"], respuestaCorrecta: 3, explicacion: "Merge Sort tiene una complejidad garantizada de O(n log n) en todos los casos, utilizando la estrategia de dividir y vencerás." },
  { id: 218, curso: "Algoritmia", pregunta: "¿Qué es la notación O(1)?", opciones: ["Tiempo lineal.", "Tiempo constante; el algoritmo tarda lo mismo sin importar el tamaño de la entrada.", "Tiempo logarítmico.", "Tiempo cuadrático.", "Tiempo exponencial."], respuestaCorrecta: 1, explicacion: "Es la complejidad más eficiente. Ejemplo: acceder a un elemento de un arreglo por su índice." },
  { id: 219, curso: "Algoritmia", pregunta: "¿Qué es un algoritmo voraz (greedy)?", opciones: ["Un algoritmo que prueba todas las combinaciones posibles.", "Un algoritmo que toma la decisión óptima local en cada paso con la esperanza de encontrar el óptimo global.", "Un algoritmo que usa recursión.", "Un algoritmo que ordena datos.", "Un algoritmo que no termina."], respuestaCorrecta: 1, explicacion: "No siempre garantiza la solución óptima global, pero es muy eficiente (ej. algoritmo de Dijkstra o el cambio de monedas)." },
  { id: 220, curso: "Algoritmia", pregunta: "¿Qué es la programación dinámica?", opciones: ["Escribir código rápidamente.", "Una técnica que resuelve problemas complejos dividiéndolos en subproblemas más simples y almacenando sus resultados para evitar recalcularlos.", "Un tipo de bucle.", "Un lenguaje de programación.", "Una estructura de datos."], respuestaCorrecta: 1, explicacion: "Optimiza algoritmos recursivos mediante memoización o tabulación, reduciendo la complejidad temporal (ej. sucesión de Fibonacci)." },
  { id: 221, curso: "Red Hat System Administration I", pregunta: "¿Qué comando usarías para ver el uso de espacio en disco de un directorio específico?", opciones: ["df", "du -sh /ruta", "ls -l", "free -m", "top"], respuestaCorrecta: 1, explicacion: "du (disk usage) con -s (summarize) y -h (human-readable) muestra el tamaño total de un directorio." },
  { id: 222, curso: "Red Hat System Administration I", pregunta: "¿Qué es un inodo (inode)?", opciones: ["Un archivo de texto.", "Una estructura de datos en el sistema de archivos que almacena metadatos de un archivo (permisos, propietario, ubicación), pero no su nombre.", "Un tipo de usuario.", "Un servicio de red.", "Un comando de Linux."], respuestaCorrecta: 1, explicacion: "El nombre del archivo es un enlace al número de inodo en el directorio." },
  { id: 223, curso: "Red Hat System Administration I", pregunta: "¿Cómo buscarías archivos con un nombre parcial en todo el sistema?", opciones: ["locate", "find / -name '*nombre*'", "search", "grep", "whereis"], respuestaCorrecta: 1, explicacion: "find es la herramienta más potente y precisa para buscar archivos en tiempo real basándose en diversos criterios." },
  { id: 224, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia hay entre su y sudo?", opciones: ["Son lo mismo.", "su cambia completamente al usuario (pidiendo su contraseña); sudo ejecuta un comando específico con privilegios de otro usuario (usualmente root) usando tu propia contraseña.", "sudo es más antiguo.", "su no requiere contraseña.", "sudo solo funciona en Ubuntu."], respuestaCorrecta: 1, explicacion: "sudo es más seguro y auditable, ya que otorga privilegios temporales y específicos sin compartir la contraseña de root." },
  { id: 225, curso: "Red Hat System Administration I", pregunta: "¿Qué utilidad tiene visudo?", opciones: ["Ver el archivo sudoers.", "Editar el archivo /etc/sudoers de forma segura, verificando la sintaxis antes de guardar para evitar bloquear el acceso root.", "Ver los usuarios conectados.", "Cambiar la contraseña.", "Listar los servicios."], respuestaCorrecta: 1, explicacion: "Editar sudoers con un editor normal (como nano o vim directamente) puede causar errores de sintaxis que impiden usar sudo." },
  { id: 226, curso: "Red Hat System Administration I", pregunta: "¿Cómo comprimirías un directorio usando tar y gzip?", opciones: ["tar -cvf archivo.tar dir", "tar -czvf archivo.tar.gz dir", "zip -r archivo.zip dir", "gzip dir", "compress dir"], respuestaCorrecta: 1, explicacion: "La 'z' indica compresión gzip, 'c' crear, 'v' verboso, 'f' archivo." },
  { id: 227, curso: "Red Hat System Administration I", pregunta: "¿Cómo listarías el contenido de un archivo .tar.gz sin extraerlo?", opciones: ["tar -xzvf archivo.tar.gz", "tar -tzvf archivo.tar.gz", "cat archivo.tar.gz", "ls archivo.tar.gz", "unzip -l archivo.tar.gz"], respuestaCorrecta: 1, explicacion: "La opción 't' (list) muestra el contenido del archivo empaquetado sin extraer los archivos al disco." },
  { id: 228, curso: "Red Hat System Administration I", pregunta: "¿Cómo verificarías qué versión del kernel está ejecutando el sistema?", opciones: ["kernel -v", "uname -r", "version", "cat /proc/cpuinfo", "lsb_release -a"], respuestaCorrecta: 1, explicacion: "uname -r (release) muestra específicamente la versión del kernel de Linux en uso." },
  { id: 229, curso: "CCNA M1", pregunta: "¿Qué es la latencia?", opciones: ["La cantidad de datos que se pueden enviar.", "El retraso o tiempo que tarda un paquete en viajar desde el origen hasta el destino.", "La pérdida de paquetes.", "La velocidad del cable.", "El ancho de banda."], respuestaCorrecta: 1, explicacion: "Se mide generalmente en milisegundos (ms) y es crucial para aplicaciones en tiempo real como VoIP o juegos." },
  { id: 230, curso: "CCNA M1", pregunta: "¿Cuál es el tamaño mínimo de una trama Ethernet?", opciones: ["32 bytes", "64 bytes", "128 bytes", "1518 bytes", "2048 bytes"], respuestaCorrecta: 1, explicacion: "64 bytes es el mínimo para garantizar la detección de colisiones en redes Ethernet tradicionales." },
  { id: 231, curso: "CCNA M1", pregunta: "¿Cuál es el tamaño máximo de una trama Ethernet estándar (sin jumbo frames)?", opciones: ["512 bytes", "1024 bytes", "1518 bytes", "2048 bytes", "4096 bytes"], respuestaCorrecta: 2, explicacion: "1518 bytes incluye el encabezado, los datos (MTU de 1500) y la secuencia de verificación de trama (FCS)." },
  { id: 232, curso: "CCNA M2", pregunta: "¿Qué es una VLAN nativa?", opciones: ["La VLAN con el número más alto.", "La VLAN cuyos paquetes no llevan etiqueta (untagged) al salir por un puerto troncal. Por defecto es la VLAN 1.", "Una VLAN que no se puede borrar.", "Una VLAN de voz.", "Una VLAN de administración."], respuestaCorrecta: 1, explicacion: "Ambos extremos de un enlace troncal deben tener la misma VLAN nativa configurada para evitar problemas de seguridad y enrutamiento." },
  { id: 233, curso: "CCNA M2", pregunta: "¿Cómo selecciona STP el Root Bridge?", opciones: ["Aleatoriamente.", "El switch con la Prioridad de Puente más baja; en caso de empate, el que tenga la dirección MAC más baja.", "El switch con más puertos.", "El switch más nuevo.", "El switch configurado manualmente como 'master'."], respuestaCorrecta: 1, explicacion: "El Root Bridge es el punto de referencia lógico de la topología STP." },
  { id: 234, curso: "CCNA M2", pregunta: "¿Qué es inter-VLAN routing?", opciones: ["Enrutar tráfico dentro de la misma VLAN.", "La capacidad de enrutar tráfico de red entre diferentes VLANs, requiriendo un dispositivo de Capa 3 (router o switch multicapa).", "Un tipo de cable.", "Un protocolo de seguridad.", "Una función de Capa 2."], respuestaCorrecta: 1, explicacion: "Las VLANs son dominios de broadcast separados; se necesita Capa 3 para que se comuniquen entre sí." },
  { id: 235, curso: "CCNA M2", pregunta: "¿Qué es Router-on-a-Stick?", opciones: ["Un router roto.", "Una configuración donde una sola interfaz física del router se subdivide en subinterfaces lógicas, cada una asignada a una VLAN diferente.", "Un tipo de switch.", "Un protocolo de enrutamiento.", "Una VLAN nativa."], respuestaCorrecta: 1, explicacion: "Permite el enrutamiento inter-VLAN usando un solo enlace troncal hacia el router." },
  { id: 236, curso: "CCNA M3", pregunta: "¿Qué es una ruta resumen manual?", opciones: ["Una ruta aprendida por OSPF.", "Una ruta estática configurada que representa a múltiples redes contiguas con una sola entrada de máscara más corta.", "Una ruta por defecto.", "Una ruta dinámica.", "Una ruta flotante."], respuestaCorrecta: 1, explicacion: "Reduce el tamaño de la tabla de enrutamiento y mejora la estabilidad de la red al ocultar fluctuaciones de redes específicas." },
  { id: 237, curso: "CCNA M3", pregunta: "¿Qué es un área stub en OSPF?", opciones: ["Un área que conecta a Internet.", "Un área que no recibe rutas externas (Tipo 5 LSA) del ASBR, usando una ruta por defecto para salir del área.", "Un área con muchos routers.", "Un área sin switch.", "Un área de backbone."], respuestaCorrecta: 1, explicacion: "Reduce el tamaño de la LSDB y la sobrecarga de CPU/memoria en routers con recursos limitados." },
  { id: 238, curso: "CCNA M3", pregunta: "¿Qué es un ABR (Area Border Router)?", opciones: ["Un router que conecta una red LAN a Internet.", "Un router que tiene interfaces en múltiples áreas OSPF, conectando el área backbone con otras áreas.", "Un switch de capa 2.", "Un servidor DNS.", "Un firewall."], respuestaCorrecta: 1, explicacion: "El ABR es responsable de resumir y propagar la información de enrutamiento entre áreas." },
  { id: 239, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace el atributo required en un input de formulario?", opciones: ["Oculta el campo.", "Impide que el formulario se envíe si el campo está vacío.", "Pone el campo en solo lectura.", "Cambia el color del campo.", "Envía el formulario automáticamente."], respuestaCorrecta: 1, explicacion: "Es una validación nativa de HTML5 que asegura que el usuario complete el campo antes de la sumisión." },
  { id: 240, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre readonly y disabled en un input?", opciones: ["No hay diferencia.", "readonly permite que el valor se envíe con el formulario pero no se puede editar; disabled no envía el valor y se ve atenuado.", "disabled es más seguro.", "readonly no funciona en móviles.", "disabled permite edición."], respuestaCorrecta: 1, explicacion: "Los campos 'disabled' se excluyen completamente de la petición HTTP al enviar el formulario." },
  { id: 241, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es un evento en JavaScript?", opciones: ["Un error en el código.", "Una acción o suceso que ocurre en el navegador (ej. clic, tecla presionada, carga de página) al que el código puede responder.", "Una variable.", "Una función matemática.", "Un tipo de dato."], respuestaCorrecta: 1, explicacion: "Los eventos son la base de la interactividad web, permitiendo que la página reaccione al usuario." },
  { id: 242, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace el método map() en un arreglo de JavaScript?", opciones: ["Modifica el arreglo original.", "Crea un nuevo arreglo con los resultados de aplicar una función proporcionada a cada uno de los elementos del arreglo original.", "Filtra elementos.", "Ordena el arreglo.", "Elimina el último elemento."], respuestaCorrecta: 1, explicacion: "Es una herramienta fundamental de la programación funcional en JS para transformar datos sin mutar el original." },
  { id: 243, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué hace el método filter()?", opciones: ["Ordena el arreglo.", "Crea un nuevo arreglo con todos los elementos que pasen la prueba implementada por la función proporcionada.", "Cambia los valores.", "Une dos arreglos.", "Busca un elemento."], respuestaCorrecta: 1, explicacion: "Devuelve un subconjunto del arreglo original que cumple con la condición especificada." },
  { id: 244, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una promesa (Promise) en JavaScript?", opciones: ["Una variable global.", "Un objeto que representa la terminación o el fracaso eventual de una operación asíncrona y su valor resultante.", "Un tipo de bucle.", "Una función flecha.", "Un evento del DOM."], respuestaCorrecta: 1, explicacion: "Permite manejar operaciones asíncronas (como peticiones de red) de manera más limpia que los callbacks." },
  { id: 245, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué problema resuelve async/await?", opciones: ["Hace que el código sea síncrono.", "Permite escribir código asíncrono basado en promesas con una sintaxis que parece síncrona, mejorando la legibilidad.", "Elimina la necesidad de funciones.", "Acelera la ejecución del código.", "Evita el uso de variables."], respuestaCorrecta: 1, explicacion: "Evita el 'callback hell' o el encadenamiento excesivo de .then(), haciendo el flujo del código más fácil de seguir." },
  { id: 246, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una aplicación web de arquitectura cliente-servidor?", opciones: ["Una app que solo funciona sin internet.", "Un modelo donde el cliente (navegador) solicita recursos o servicios, y el servidor los procesa y responde.", "Una base de datos local.", "Un sistema operativo.", "Un protocolo de enrutamiento."], respuestaCorrecta: 1, explicacion: "Es la base de la web moderna: el frontend (cliente) pide datos, el backend (servidor) los procesa y los envía." },
  { id: 247, curso: "Algoritmia", pregunta: "¿Qué es una función pura?", opciones: ["Una función que no tiene parámetros.", "Una función que, dada la misma entrada, siempre devuelve la misma salida y no tiene efectos secundarios observables.", "Una función que modifica variables globales.", "Una función que imprime en pantalla.", "Una función recursiva."], respuestaCorrecta: 1, explicacion: "Son fundamentales en la programación funcional, ya que son predecibles y fáciles de probar." },
  { id: 248, curso: "Algoritmia", pregunta: "¿Qué es un efecto secundario (side effect) en programación?", opciones: ["Un error de compilación.", "Cualquier modificación del estado externo a la función (ej. modificar una variable global, escribir en un archivo, imprimir en pantalla).", "Un bucle infinito.", "Una variable no inicializada.", "Un comentario en el código."], respuestaCorrecta: 1, explicacion: "Las funciones con efectos secundarios son más difíciles de depurar porque su comportamiento depende del estado del sistema." },
  { id: 249, curso: "Algoritmia", pregunta: "¿Qué es la memoización?", opciones: ["Recordar la contraseña.", "Una técnica de optimización que almacena los resultados de llamadas a funciones costosas y devuelve el resultado en caché cuando se vuelven a llamar con las mismas entradas.", "Un tipo de variable.", "Un algoritmo de ordenamiento.", "Una estructura de control."], respuestaCorrecta: 1, explicacion: "Es una forma específica de caché aplicada a funciones, clave en la programación dinámica." },
  { id: 250, curso: "Algoritmia", pregunta: "¿Qué diferencia hay entre un arreglo y una lista enlazada?", opciones: ["No hay diferencia.", "El arreglo tiene tamaño fijo y memoria contigua; la lista enlazada tiene tamaño dinámico y sus nodos están dispersos en memoria, conectados por punteros.", "La lista enlazada es más rápida para acceder a un índice.", "El arreglo no puede almacenar números.", "La lista enlazada es un tipo de variable."], respuestaCorrecta: 1, explicacion: "Los arreglos permiten acceso aleatorio O(1), mientras que las listas enlazadas son eficientes para inserciones/eliminaciones O(1) en la cabeza." },
  { id: 251, curso: "Red Hat System Administration I", pregunta: "¿Qué es un proceso zombie?", opciones: ["Un virus.", "Un proceso que ha terminado su ejecución pero cuya entrada aún permanece en la tabla de procesos porque el proceso padre no ha leído su estado de salida.", "Un proceso que consume mucha CPU.", "Un proceso en segundo plano.", "Un servicio de systemd."], respuestaCorrecta: 1, explicacion: "No consume recursos de CPU o memoria, pero ocupa un espacio en la tabla de procesos (PID) hasta que el padre lo 'recolecta'." },
  { id: 252, curso: "Red Hat System Administration I", pregunta: "¿Qué es un proceso huérfano?", opciones: ["Un proceso sin permisos.", "Un proceso cuyo proceso padre ha terminado, por lo que es adoptado automáticamente por el proceso init o systemd (PID 1).", "Un proceso zombie.", "Un proceso en primer plano.", "Un script de bash."], respuestaCorrecta: 1, explicacion: "El sistema se encarga de limpiarlos, por lo que no son tan problemáticos como los zombies." },
  { id: 253, curso: "Red Hat System Administration I", pregunta: "¿Cómo investigarías si una tarea programada con cron no se ejecutó?", opciones: ["Revisando /var/log/cron o usando journalctl -u crond.", "Ejecutando top.", "Mirando el escritorio.", "Usando ping.", "Revisando /etc/passwd."], respuestaCorrecta: 0, explicacion: "Los logs del demonio cron registran cada vez que se dispara una tarea y si hubo errores." },
  { id: 254, curso: "Red Hat System Administration I", pregunta: "¿Qué ventaja tienen los systemd timers frente a cron?", opciones: ["Son más difíciles de usar.", "Permiten una programación más precisa (ej. '15 minutos después del arranque'), dependen de unidades de servicio y tienen mejor registro en journalctl.", "No tienen ventajas.", "Solo funcionan en Ubuntu.", "No permiten tareas repetitivas."], respuestaCorrecta: 1, explicacion: "Los timers están integrados en el ecosistema systemd, ofreciendo mayor flexibilidad y monitoreo que el cron tradicional." },
  { id: 255, curso: "Red Hat System Administration I", pregunta: "¿Cómo detectarías un proceso que está consumiendo demasiada memoria de forma anormal?", opciones: ["Usando df -h.", "Usando top o htop y observando la columna RES o %MEM.", "Usando ping.", "Usando cat /etc/fstab.", "Usando ls -l."], respuestaCorrecta: 1, explicacion: "top/htop muestran en tiempo real el consumo de recursos por proceso, permitiendo identificar fugas de memoria." },
  { id: 256, curso: "Red Hat System Administration I", pregunta: "¿Qué es LVM (Logical Volume Manager)?", opciones: ["Un tipo de archivo.", "Un sistema de gestión de volúmenes que permite crear particiones lógicas flexibles que pueden redimensionarse dinámicamente sin perder datos.", "Un protocolo de red.", "Un firewall.", "Un gestor de arranque."], respuestaCorrecta: 1, explicacion: "LVM abstrae el almacenamiento físico, permitiendo agrupar discos y expandir volúmenes lógicos fácilmente." },
  { id: 257, curso: "Red Hat System Administration I", pregunta: "¿Cómo ampliarías un volumen lógico sin perder datos?", opciones: ["Borrando y creando de nuevo.", "Usando lvextend para ampliar el volumen y luego resize2fs o xfs_growfs para expandir el sistema de archivos.", "No se puede hacer.", "Reinstalando el sistema.", "Usando rm -rf."], respuestaCorrecta: 1, explicacion: "LVM permite el crecimiento en caliente (online) de los sistemas de archivos, una de sus mayores ventajas." },
  { id: 258, curso: "Red Hat System Administration I", pregunta: "¿Qué comando usarías para revisar el consumo de inodos?", opciones: ["df -i", "du -h", "ls -l", "free -m", "top"], respuestaCorrecta: 0, explicacion: "df -i muestra el uso de inodos en lugar del uso de bloques de disco, útil para diagnosticar el error 'No space left on device' cuando hay espacio libre pero no inodos." },
  { id: 259, curso: "Red Hat System Administration I", pregunta: "¿Qué son las ACLs (Access Control Lists) en Linux?", opciones: ["Listas de control de acceso que permiten otorgar permisos más granulares y específicos a usuarios o grupos más allá de los permisos tradicionales de propietario/grupo/otros.", "Listas de paquetes instalados.", "Reglas de firewall.", "Logs del sistema.", "Tablas de enrutamiento."], respuestaCorrecta: 0, explicacion: "Se gestionan con los comandos getfacl y setfacl." },
  { id: 260, curso: "Red Hat System Administration I", pregunta: "¿Cómo resolverías un sistema que arranca en modo de emergencia por un error en /etc/fstab?", opciones: ["Reinstalando Linux.", "Montando el sistema de archivos raíz como lectura/escritura, corrigiendo la línea errónea en /etc/fstab y reiniciando.", "Borrando el disco.", "Desconectando la red.", "Cambiando la contraseña de root."], respuestaCorrecta: 1, explicacion: "Un error de sintaxis o un dispositivo faltante en fststab impide el arranque normal; corregirlo en modo emergencia restaura el sistema." },
  { id: 261, curso: "CCNA M1", pregunta: "¿Qué efecto tiene NAT en la comunicación entre redes?", opciones: ["Acelera la conexión.", "Traduce direcciones IP privadas a una dirección IP pública (o viceversa), permitiendo que múltiples dispositivos compartan una sola IP pública para salir a Internet.", "Encripta el tráfico.", "Filtra virus.", "Asigna nombres de dominio."], respuestaCorrecta: 1, explicacion: "Network Address Translation es fundamental para conservar el espacio de direcciones IPv4 y proporcionar una capa básica de seguridad." },
  { id: 262, curso: "CCNA M1", pregunta: "¿Qué utilidad tiene tracert o traceroute al diagnosticar fallas?", opciones: ["Muestra la velocidad de la red.", "Muestra la ruta completa y los saltos (hops) que toma un paquete para llegar al destino, ayudando a identificar dónde se pierde la conectividad.", "Muestra la tabla MAC.", "Muestra las VLANs.", "Muestra el estado de los puertos."], respuestaCorrecta: 1, explicacion: "Utiliza el campo TTL de IP para que cada router en el camino devuelva un mensaje de 'tiempo excedido', revelando su dirección." },
  { id: 263, curso: "CCNA M2", pregunta: "¿Qué ocurre si la VLAN nativa no coincide en dos switches conectados por un troncal?", opciones: ["Nada, funciona normal.", "Se generan mensajes de error de inconsistencia de VLAN nativa (CDP) y puede haber fugas de tráfico o problemas de spanning tree.", "El enlace se apaga.", "Los switches se reinician.", "Se crea una nueva VLAN."], respuestaCorrecta: 1, explicacion: "Es una mala práctica de configuración que puede causar problemas de conectividad y vulnerabilidades de seguridad (VLAN hopping)." },
  { id: 264, curso: "CCNA M2", pregunta: "¿Qué pasa si se supera el límite de direcciones MAC en un puerto con Port Security?", opciones: ["El puerto se apaga permanentemente.", "Depende de la configuración de violación: puede proteger (drop), restringir (drop y log) o apagar (shutdown) el puerto.", "El switch se reinicia.", "Se crea una nueva VLAN.", "No pasa nada."], respuestaCorrecta: 1, explicacion: "El modo 'shutdown' es el predeterminado, requiriendo intervención administrativa (errdisable recovery) para reactivar el puerto." },
  { id: 265, curso: "CCNA M3", pregunta: "¿Qué es la redistribución de rutas?", opciones: ["Borrar las rutas.", "El proceso de compartir información de enrutamiento entre diferentes protocolos de enrutamiento (ej. de OSPF a EIGRP).", "Sumarizar rutas.", "Crear una ruta por defecto.", "Configurar una VLAN."], respuestaCorrecta: 1, explicacion: "Requiere un router de frontera que ejecute ambos protocolos y debe configurarse con cuidado para evitar bucles de enrutamiento." },
  { id: 266, curso: "CCNA M3", pregunta: "¿Cómo evitarías bucles de enrutamiento al redistribuir entre protocolos diferentes?", opciones: ["No usando protocolos dinámicos.", "Usando filtros de rutas (route-maps), modificando la distancia administrativa o la métrica para hacer una dirección preferida.", "Apagando los routers.", "Usando solo rutas estáticas.", "No es posible evitarlos."], respuestaCorrecta: 1, explicacion: "La redistribución mutua sin filtros puede hacer que las rutas aprendidas de un protocolo se reintroduzcan en él, creando un bucle." },
  { id: 267, curso: "CCNA M3", pregunta: "¿Qué es un LSA Tipo 1 en OSPF?", opciones: ["Router LSA, generado por cada router para describir sus enlaces y costos dentro de su propia área.", "Network LSA.", "Summary LSA.", "External LSA.", "NSSA External LSA."], respuestaCorrecta: 0, explicacion: "Es el bloque de construcción básico de la LSDB, y nunca se propaga más allá del área donde se originó." },
  { id: 268, curso: "CCNA M3", pregunta: "¿Qué tipo de red OSPF no elige DR/BDR y por qué?", opciones: ["Broadcast, porque es muy lenta.", "Point-to-Point, porque solo hay dos routers en el enlace y la elección de DR es innecesaria.", "NBMA, porque es muy compleja.", "Todas las redes eligen DR.", "Redes LAN."], respuestaCorrecta: 1, explicacion: "En un enlace punto a punto, la adyacencia se forma directamente sin la sobrecarga de la elección de Designated Router." },
  { id: 269, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una cookie HttpOnly?", opciones: ["Una cookie que solo funciona en HTTP.", "Una cookie que no puede ser accedida mediante JavaScript (document.cookie), mitigando el riesgo de robo de sesión por ataques XSS.", "Una cookie que expira en una hora.", "Una cookie que almacena contraseñas en texto plano.", "Una cookie de terceros."], respuestaCorrecta: 1, explicacion: "Es una bandera de seguridad crucial para las cookies de sesión." },
  { id: 270, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué diferencia hay entre localStorage y sessionStorage?", opciones: ["No hay diferencia.", "localStorage persiste incluso después de cerrar el navegador; sessionStorage se borra al cerrar la pestaña o ventana.", "sessionStorage es más grande.", "localStorage solo almacena números.", "sessionStorage se comparte entre todas las pestañas."], respuestaCorrecta: 1, explicacion: "Ambos almacenan datos en el cliente, pero su ciclo de vida es diferente." },
  { id: 271, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es XSS (Cross-Site Scripting)?", opciones: ["Un tipo de base de datos.", "Una vulnerabilidad donde un atacante inyecta scripts maliciosos en páginas web vistas por otros usuarios.", "Un framework de CSS.", "Un protocolo de red.", "Un método de ordenamiento."], respuestaCorrecta: 1, explicacion: "Se previene escapando (sanitizando) la entrada del usuario y usando Content Security Policy (CSP)." },
  { id: 272, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es CORS (Cross-Origin Resource Sharing)?", opciones: ["Un tipo de archivo.", "Un mecanismo de seguridad del navegador que permite o restringe las solicitudes de recursos a un dominio diferente al que sirvió la página web.", "Un lenguaje de programación.", "Un servidor web.", "Una base de datos."], respuestaCorrecta: 1, explicacion: "Previene que un sitio web malicioso lea datos sensibles de otro sitio web en nombre del usuario." },
  { id: 273, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una SPA (Single Page Application)?", opciones: ["Una página con mucho texto.", "Una aplicación web que carga una única página HTML y actualiza dinámicamente el contenido a medida que el usuario interactúa, sin recargar la página completa.", "Un sitio web estático.", "Una base de datos.", "Un sistema operativo."], respuestaCorrecta: 1, explicacion: "Frameworks como React, Angular o Vue se usan para construir SPAs, ofreciendo una experiencia similar a una app de escritorio." },
  { id: 274, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es una closure (clausura) en JavaScript?", opciones: ["Una etiqueta HTML.", "Una función que recuerda y tiene acceso a su ámbito léxico (variables), incluso cuando la función se ejecuta fuera de ese ámbito.", "Un bucle.", "Un tipo de dato.", "Un evento."], respuestaCorrecta: 1, explicacion: "Es un concepto poderoso para la encapsulación de datos y la creación de fábricas de funciones." },
  { id: 275, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es el Event Loop en JavaScript?", opciones: ["Un bucle for infinito.", "El mecanismo que permite a JavaScript realizar operaciones no bloqueantes, moviendo tareas asíncronas de la cola de tareas a la pila de llamadas cuando esta está vacía.", "Un tipo de variable.", "Un método de arreglo.", "Una función del DOM."], respuestaCorrecta: 1, explicacion: "Es el corazón de la asincronía en JS, permitiendo que el hilo principal no se congele mientras espera peticiones de red o temporizadores." },
  { id: 276, curso: "Algoritmia", pregunta: "¿Qué es un invariante de ciclo?", opciones: ["Una variable que no cambia de nombre.", "Una condición que es verdadera antes y después de cada iteración de un ciclo, usada para probar la corrección de un algoritmo.", "Un bucle infinito.", "Un error de sintaxis.", "Una función recursiva."], respuestaCorrecta: 1, explicacion: "Es una herramienta formal de verificación para demostrar que un algoritmo hace lo que se supone que debe hacer." },
  { id: 277, curso: "Algoritmia", pregunta: "¿Qué es la subestructura óptima?", opciones: ["Un tipo de red.", "Una propiedad de un problema donde la solución óptima al problema contiene dentro de sí las soluciones óptimas a sus subproblemas.", "Un algoritmo de ordenamiento.", "Una estructura de datos.", "Un tipo de variable."], respuestaCorrecta: 1, explicacion: "Es una de las dos condiciones necesarias (junto con subproblemas superpuestos) para aplicar programación dinámica." },
  { id: 278, curso: "Algoritmia", pregunta: "¿Qué diferencia hay entre DFS y BFS?", opciones: ["No hay diferencia.", "DFS (Depth-First Search) explora lo más profundo posible a lo largo de cada rama antes de retroceder; BFS (Breadth-First Search) explora todos los vecinos de un nivel antes de pasar al siguiente.", "BFS usa recursión y DFS no.", "DFS es solo para grafos dirigidos.", "BFS es más lento siempre."], respuestaCorrecta: 1, explicacion: "DFS usa una pila (o recursión) y es bueno para detectar ciclos; BFS usa una cola y encuentra el camino más corto en grafos no ponderados." },
  { id: 279, curso: "Algoritmia", pregunta: "¿Qué es un árbol binario de búsqueda (BST)?", opciones: ["Un árbol donde cada nodo tiene hasta dos hijos, y el subárbol izquierdo contiene solo valores menores y el derecho solo valores mayores que el nodo.", "Un árbol con tres hijos por nodo.", "Un arreglo unidimensional.", "Un tipo de bucle.", "Una función matemática."], respuestaCorrecta: 0, explicacion: "Esta propiedad permite búsquedas, inserciones y eliminaciones eficientes con una complejidad promedio de O(log n)." },
  { id: 280, curso: "Algoritmia", pregunta: "¿Qué es el problema de la mochila 0/1?", opciones: ["Un problema de ordenamiento.", "Un problema de optimización donde se debe seleccionar un subconjunto de objetos con peso y valor, para maximizar el valor total sin exceder una capacidad de peso dada, sin fraccionar objetos.", "Un problema de búsqueda.", "Un problema de recursión infinita.", "Un problema de red."], respuestaCorrecta: 1, explicacion: "Es el ejemplo clásico que se resuelve eficientemente usando programación dinámica." },
  { id: 281, curso: "Red Hat System Administration I", pregunta: "¿Qué comando usarías para ver el historial de comandos ejecutados por un usuario?", opciones: ["history", "log", "past", "commands", "list"], respuestaCorrecta: 0, explicacion: "El comando history muestra la lista de comandos previamente ejecutados en la sesión actual, almacenados en ~/.bash_history." },
  { id: 282, curso: "Red Hat System Administration I", pregunta: "¿Cómo bloquearías temporalmente una cuenta de usuario?", opciones: ["usermod -L usuario", "usermod -U usuario", "passwd -u usuario", "rm -rf /home/usuario", "deluser usuario"], respuestaCorrecta: 0, explicacion: "La opción -L (lock) coloca un '!' delante de la contraseña encriptada en /etc/shadow, impidiendo el inicio de sesión." },
  { id: 283, curso: "Red Hat System Administration I", pregunta: "¿Qué diferencia existe entre cp -r y cp -a?", opciones: ["No hay diferencia.", "cp -r copia recursivamente; cp -a copia recursivamente preservando todos los atributos (permisos, timestamps, enlaces simbólicos, etc.), equivalente a -dR --preserve=all.", "cp -a es más lento.", "cp -r preserva permisos y cp -a no.", "cp -a solo funciona en redes."], respuestaCorrecta: 1, explicacion: "cp -a (archive) es la opción recomendada para hacer copias de seguridad o duplicar estructuras de directorios fielmente." },
  { id: 284, curso: "Red Hat System Administration I", pregunta: "¿Cómo establecerías una fecha de expiración para una cuenta de usuario?", opciones: ["usermod -e AAAA-MM-DD usuario", "passwd -e usuario", "chage -E AAAA-MM-DD usuario", "Ambas A y C son correctas.", "No se puede hacer."], respuestaCorrecta: 3, explicacion: "Tanto usermod -e como chage -E permiten definir una fecha tras la cual la cuenta quedará deshabilitada automáticamente." },
  { id: 285, curso: "Red Hat System Administration I", pregunta: "¿Qué hace blkid?", opciones: ["Muestra el espacio en disco.", "Localiza e imprime atributos de dispositivos de bloque, como UUID y TYPE (sistema de archivos).", "Formatea un disco.", "Crea una partición.", "Monta un dispositivo."], respuestaCorrecta: 1, explicacion: "Es muy útil para obtener el UUID de una partición y usarlo en /etc/fstab para montajes persistentes y seguros." },
  { id: 286, curso: "CCNA M1", pregunta: "¿Qué diferencia hay entre una dirección unicast, multicast y broadcast?", opciones: ["Son lo mismo.", "Unicast es de uno a uno, multicast de uno a muchos (grupo suscrito), broadcast de uno a todos en el dominio de broadcast.", "Broadcast es de uno a uno.", "Multicast es de todos a todos.", "Unicast es de uno a todos."], respuestaCorrecta: 1, explicacion: "Son los tres modos fundamentales de transmisión de datos en una red IP." },
  { id: 287, curso: "CCNA M2", pregunta: "¿Qué significa que una interfaz esté en estado 'up/down'?", opciones: ["La interfaz está funcionando perfectamente.", "La Capa 1 (física) está activa (up), pero la Capa 2 (protocolo de enlace de datos) está inactiva (down), usualmente por falta de clock rate, encapsulación no coincidente o falta de keepalives.", "La interfaz está apagada administrativamente.", "El cable está desconectado.", "La interfaz está en modo de espera."], respuestaCorrecta: 1, explicacion: "Indica un problema de configuración de Capa 2 o de protocolo, a pesar de que hay señal física." },
  { id: 288, curso: "CCNA M3", pregunta: "¿Qué es IP SLA?", opciones: ["Un protocolo de enrutamiento.", "Una característica de Cisco IOS que permite al router generar tráfico de prueba (ej. ICMP, HTTP) para monitorear el rendimiento y la disponibilidad de la red en tiempo real.", "Un tipo de cable.", "Una VLAN.", "Un firewall."], respuestaCorrecta: 1, explicacion: "Se usa comúnmente con rutas estáticas flotantes (track) para conmutar automáticamente a un enlace de respaldo si el principal falla." },
  { id: 289, curso: "CCNA M3", pregunta: "¿Qué es route poisoning (envenenamiento de rutas)?", opciones: ["Un ataque de hackers.", "Una técnica de protocolos de vector distancia (como RIP) donde una ruta fallida se anuncia con una métrica infinita (ej. 16 en RIP) para informar rápidamente a los vecinos de que la red es inalcanzable.", "Una configuración de OSPF.", "Un tipo de cable.", "Un protocolo de seguridad."], respuestaCorrecta: 1, explicacion: "Acelera la convergencia al invalidar inmediatamente la ruta en lugar de esperar a que expire el temporizador." },
  { id: 290, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es la idempotencia en métodos HTTP?", opciones: ["Que el método es rápido.", "Que realizar la misma petición múltiples veces tiene el mismo efecto en el servidor que realizarla una sola vez (ej. GET, PUT, DELETE).", "Que el método es seguro.", "Que el método encripta datos.", "Que el método no se puede usar."], respuestaCorrecta: 1, explicacion: "POST no es idempotente, ya que enviar el mismo formulario dos veces podría crear dos registros duplicados." },
  { id: 291, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es el renderizado del lado del servidor (SSR)?", opciones: ["Renderizar la página en el navegador del cliente.", "Generar el HTML completo de la página en el servidor y enviarlo al cliente, mejorando el SEO y el tiempo de carga inicial.", "Usar solo CSS.", "Usar solo JavaScript.", "Una base de datos."], respuestaCorrecta: 1, explicacion: "Frameworks como Next.js (React) o Nuxt.js (Vue) popularizan el SSR para combinar las ventajas del SEO con la interactividad del cliente." },
  { id: 292, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es el lazy loading (carga diferida)?", opciones: ["Cargar todo al inicio.", "Una técnica para retrasar la carga de recursos no críticos (como imágenes fuera de la pantalla) hasta que el usuario se desplaza cerca de ellos, mejorando el rendimiento inicial.", "Un tipo de variable.", "Un bucle.", "Un evento."], respuestaCorrecta: 1, explicacion: "Se puede implementar nativamente en HTML con el atributo loading='lazy' en las etiquetas <img>." },
  { id: 293, curso: "Fundamentos de Desarrollo Web", pregunta: "¿Qué es un JWT (JSON Web Token)?", opciones: ["Un tipo de archivo.", "Un estándar abierto para transmitir información de forma segura entre partes como un objeto JSON, firmado digitalmente, usado comúnmente para autenticación.", "Una base de datos.", "Un framework de CSS.", "Un servidor web."], respuestaCorrecta: 1, explicacion: "Permite la autenticación sin estado (stateless) en APIs, ya que el token contiene toda la información necesaria y está firmado para prevenir manipulaciones." },
  { id: 294, curso: "Algoritmia", pregunta: "¿Qué es un grafo en estructuras de datos?", opciones: ["Un tipo de gráfico de barras.", "Una colección de nodos (vértices) conectados por aristas (edges), que puede ser dirigido o no dirigido, ponderado o no ponderado.", "Un arreglo unidimensional.", "Una lista enlazada simple.", "Un tipo de variable."], respuestaCorrecta: 1, explicacion: "Los grafos modelan relaciones entre objetos, como redes sociales, mapas de carreteras o dependencias de tareas." },
  { id: 295, curso: "Algoritmia", pregunta: "¿Qué es el backtracking (vuelta atrás)?", opciones: ["Un bucle infinito.", "Una técnica algorítmica para resolver problemas recursivamente probando construir una solución paso a paso, y abandonando un camino (haciendo backtrack) tan pronto como determina que no puede llevar a una solución válida.", "Un tipo de variable.", "Un método de ordenamiento.", "Una estructura de control."], respuestaCorrecta: 1, explicacion: "Es como un laberinto: si llegas a un callejón sin salida, retrocedes al último cruce y pruebas otro camino." },
  { id: 296, curso: "Algoritmia", pregunta: "¿Qué es la complejidad espacial O(n)?", opciones: ["El algoritmo no usa memoria extra.", "El algoritmo requiere una cantidad de memoria adicional que crece linealmente con el tamaño de la entrada.", "El algoritmo usa memoria constante.", "El algoritmo usa memoria cuadrática.", "El algoritmo no termina."], respuestaCorrecta: 1, explicacion: "Ejemplo: crear un arreglo de copia del mismo tamaño que el arreglo de entrada." },
  { id: 297, curso: "Red Hat System Administration I", pregunta: "¿Qué es un target en systemd?", opciones: ["Un archivo de configuración.", "Un punto de sincronización que agrupa unidades (como runlevels en SysVinit) para llevar el sistema a un estado específico (ej. multi-user.target, graphical.target).", "Un tipo de usuario.", "Un servicio de red.", "Un firewall."], respuestaCorrecta: 1, explicacion: "Los targets permiten definir el estado deseado del sistema durante el arranque o en tiempo de ejecución." },
  { id: 298, curso: "Red Hat System Administration I", pregunta: "¿Cómo recargarías systemd después de modificar un archivo de servicio?", opciones: ["systemctl restart systemd", "systemctl daemon-reload", "reboot", "systemctl reload", "init 6"], respuestaCorrecta: 1, explicacion: "daemon-reload le dice a systemd que vuelva a leer los archivos de configuración de las unidades sin interrumpir los servicios en ejecución." },
  { id: 299, curso: "CCNA M3", pregunta: "¿Qué es una área totally stubby en OSPF?", opciones: ["Un área que recibe todas las rutas externas.", "Un área que no recibe rutas externas (Tipo 5) ni rutas resumidas de otras áreas (Tipo 3), dependiendo únicamente de una ruta por defecto inyectada por el ABR.", "Un área sin routers.", "Un área de backbone.", "Un área con muchos switches."], respuestaCorrecta: 1, explicacion: "Es la forma más restrictiva de área stub, minimizando al máximo el tamaño de la LSDB en routers de sucursales remotas." },
  { id: 300, curso: "Algoritmia", pregunta: "¿Qué es la tabulación (tabulation) en programación dinámica?", opciones: ["Usar espacios en el código.", "Un enfoque 'bottom-up' (de abajo hacia arriba) que resuelve el problema llenando una tabla (array) iterativamente, comenzando por los subproblemas más pequeños.", "Un tipo de recursión.", "Un método de ordenamiento.", "Una estructura de control."], respuestaCorrecta: 1, explicacion: "A diferencia de la memoización (top-down con recursión), la tabulación evita la sobrecarga de las llamadas a la pila de funciones." }
];